INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750515606', 'Deliduman', 'Emrah Serbes', '9789750515606', '9750515609', 'Iletisim Yayincilik', NULL, 350, 'On yedi yasindaki Caglar Iyice konusuyor. Kiz kardesi Cigdem i, onu meshur etme umitlerini, belediye baskani dayisini, yakin arkadasi Mikrop Cengiz i, tasra muhabbetlerini, depresyonun esigindeki annesini, eski sevgilisini, hic unutamadigi dedesini, hatirlarken kahrettigi babasini anlatiyor. Deliduman, dermansiz ve guduk bir ilceden haykirmaya basliyor, Istanbul a uzaniyor. Cocuklugumuzun, hatiralarimizin ve butun sokaklarimizin uzerinden dangir dungur gecen imar ve para istahina lanet! Riyakâr dunyaya, Allahsiz sermayeye, martilara, kucuk bir kizin kalbini kiranlara isyan ediyor. Barikatlarin arkasinda, soluk soluga, yapayalniz, erken kaybeden bir delidumanin ofkesini cemkiriyor. Emrah Serbes, zamanin ruhunu, Gezi nin isyancilarini, hurriyetleri icin oksurenleri, yerinde duramayanlari, kufredenleri, aglamayi unutmak icin yumrugunu sikanlari resmediyor. Deliduman, buyuk zamanin ve her zaman kenarda kalanlarin romani. (Tanitim Bulteninden)', NULL, '2015-07-06', '9789750515606.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750724275', 'Abim Deniz', 'Can Dundar', '9789750724275', '9750724275', 'Can Publishing', 2014, 480, 'Bugune kadar ozenle saklanan fotograflar, mektuplar ve belgeler, Can Dundar''in deneyimli gazeteciligi ve Deniz''in yillarca sessiz kalan kardesi Hamdi Gezmis''in tanikligiyla birlikte ilk defa bu kitapta gun yuzune cikiyor. (Tanitim Bulteninden)', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789754030419', 'Gündelik bilmeceler', 'Partha Ghose, Dipankar Home', '9789754030419', '9754030413', NULL, 1996, 179, NULL, NULL, '2015-07-06', '9789754030419.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789756938911', 'Omer''in Cocuklugu', 'Muallim Naci', '9789756938911', '9756938919', 'Sis Yayinlari', 2014, 60, 'Omerin Cocuklugu, Muallim Nacinin kendi hayatini anlattigi bir ani kitabidir. Sekiz yasindaki bir cocugun agzindan yasadigi sehrin, cocukluk gunlerinin, geleneklerin, goreneklerin, ailesi ve cevresindeki diger insanlarin anlatildigi kitap, cocuk edebiyatinin ilk orneklerindendir. Cocuk hassasiyetinin on planda oldugu kitap samimi, simsicak ve icten bir dille yazilmistir.', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789756938928', 'Sermin', 'Tevfik Fikret', '9789756938928', '9756938927', 'Sis Yayinlari', 2010, 60, 'Sermin, Tevfik Fikretin cocuklar icin yazdigi siirlerden olusan bir kitaptir. Bu siirler, cok sade ve sicak bir dille, duru bir Turkce ile yazilmis ve devrinde cok begenilmistir. Bu kitapta yer alan siirlerinde, Tevfik Fikret, cocuklari dogruluga, calismaya, kardeslige, insanlari sevmeye yonlendirmek istemekte, onlari iyi birer insan olmaya hazirlayacak duygulari islemektedir. Bunu yaparken de cocuk ruhunu ve cocuk dunyasini cok basarili bir sekilde yakalamistir.', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789756938904', 'Vatan Yahut Silistre', 'Namik Kemal', '9789756938904', '9756938900', 'Sis Yayinlari', 2010, 72, 'Vatan Yahut Silistre, Namik Kemalin ilk piyesidir. Eserde vatanperverlik ve kahramanlik duygularini islemekte, halkta bu duygulari harekete gecirmek istemektedir. Piyes, 1853 yilinda Osmanli Imparatorlugu ve Rusya arasinda baslayan Kirim Savasi`nda gonullu olarak cepheye giden Islam Bey ile asker kiligina girerek kimseye haber vermeden onun ardindan Silistreye giden sevgilisi Zekiyenin basindan gecenleri anlatir. Turk askerinin vatan ugruna gosterdigi fedakarligi canlandirir.', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786055539689', 'Hamlet', 'William Shakespeare', '9786055539689', '6055539683', 'Paraf Yayinlari', 2011, 256, 'Hamlet, William Shakespeare tarafindan 1599-1601 yillari arasinda yazildigina inanilan bir trajedidir. Oyunun konusu Hamlet''in babasini olduren, annesiyle evlenen ve Danimarka tahtina gecen amcasi Caludius''tan intikam alma cabasidir. Oyun gercek bir kederden bir gazaba donusen hayati, yapmacik bir delilikle gercek delilik arasindaki gecisleri, ensest iliskileri, ihaneti, ofkeyi, ahlaksizligi ele alir. Hamlet, Shakespeare''in en cok merak uyandiran ve ilgiyle okunan eserlerinden biridir suphesiz. Shakespeare''in Hamlet''in agzindan soyledikleri tum dunyada yuzyillardir yankilanmaktadir: "Olmak ya da olmamak." Hamlet yasamini, yasamin amacini, olumu ve olumun otesindekileri sorgulamakta ve bu dunyada akilli, soylu ve iffetli olmanin zorluklarini yansitmaktadir. Peki, Hamlet gercekten de deli miydi? Deliligi miydi ona babasini gosteren yoksa akilliligi miydi Horatio ve digerlerine bu gorumu gorduklerini soyleten?', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786054683772', 'Efsane', 'Iskender Pala', '9786054683772', '6054683772', 'Kapi Yayinlari', 2013, NULL, '(Bir ''Barbaros'' Romani) Efsaneler bazen denizden, Bazen asktan ve atesten gelirler. Asktan ve atesten ve denizden gelenler, Bazen isik olurlar ve butun zamani aydinlatirlar... Efsane kurmak kadar, efsaneyi yazmak da efsaneye dâhildir. Bir cagi haritalarda bulamazsiniz. Derine, insana ve tarihin denizlerine acilmak gerekir. Girdaplarda yuksek idealler saklanabilir. Bu kitapta Istanbul, Girnata, Madrid, Roma ve Akdeniz; ask diliyle kusatildi. Akdeniz, ask kaleminin haritasiyla yeniden cizildi. Kilic kilica, cevher celige carpti, varlik da yokluga. Ve hep bir yol vardi kalplerden denizlere. Derin denizler, buyuk asklar icin atlas olup dokundu. Iskender Pala, bir cagi ve o cagin efsanelerini dile doktu. Barbaros Hayreddin Pasa''yi... Sonra, bir gul sepeti getirdi. Isirilmis uc elmayi anlatti.', NULL, '2015-07-06', '9786054683772.jpg');
