INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750506178', 'Gölgesizler', 'Hasan Ali Toptas', '9789750506178', '9750506170', 'Iletisim Yayincilik', NULL, NULL, 'Metinlerini varolus ve yokolus uzerine kurarak varolusculugu tasraya tasimasiyla ozgunluk kazanan, tipki Kafka gibi sade dilinden yukselen muzikle giderek hayati yaziya, yaziyi ise buyulu bir hayata benzeten bir yazar... Yazma seruvenini "hayati kelime kelime genisletmek" olarak adlandiran Hasan Ali Toptas, metinlerini birer senfoniye de donusturerek, disariyla icerinin, gorunenle ic dunyanin, gerceklikle ruyalarin, somutla soyutun carpismasindan dogan tekinsiz bir atmosfere cagiriyor okurunu. Tam bir yazi ustaligiyla, Turkcenin imkânlarini sonuna kadar zorlayarak, edebiyatin buyulu dunyasina kapilar acarak... Cennet''in oglu kendini kendi varliginda yok etmisken, gercekten kadinin dedigi gibi bir kez daha yok olmussa durum kotuydu. Bu isin sonu yavas yavas koyun tamamen yok olmasina dek gidebilirdi. Belki koy zaten yoktu da bunu kimse anlayamiyordu henuz; koylulerin hepsi alismisti yokun varligina...', NULL, '2015-07-06', '9789750506178.jpg');
