INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753420310', 'Tumceler', 'Oruc Aruoba', '9789753420310', '9753420315', 'Metis Yayincilik', 2010, NULL, '1.Gunesi baska dunyalara ugurladik. 2.Gunes bulutlarin altindaysa, ya doguyordur ya da batiyor. 3.The tide and the fishermen return: Nothing is changed. 4.Git gnes; sevgilileri isit biraz da... 5.Ay saliveriyor sulari, geri donsunler diye. ...', NULL, '2015-07-06', '9789753420310.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789754032703', 'Macellanya-Ciltsiz', 'Jules Verne', '9789754032703', '975403270X', 'Tubitak Yayinlari', 2002, NULL, 'Macellanya: Dunyanin bir ucuna, issiz, hicbir yetkenin hukum surmedigi ozgur topraklar... Romanin kahramani Kaw-djer, tam bagimsizlik icinde yasayabilecegi bu topraklara gonullu surgun olmus, nereden geldigi bilinmeyen bir ozgurluk tutkunu... Jules Verne olumunden yedi yil once kaleme aldigi, hayattayken basilmayan roman Macellanya''da, kendisine oldukca benzeyen gizemli bir adamin yasadiklarini anlatiyor.', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9780140447941', 'The Iliad (Penguin Classics)', 'Homer', '9780140447941', '0140447946', 'Penguin Classics', 2003, 576, 'Newly updated by D. C. H. Rieu, son of E. V. Rieu  One of the foremost achievements in Western literature, Homer''s Iliad tells the story of the darkest episode of the Trojan War. At its center is Achilles, the greatest warrior-champion of the Greeks, and his conflict with his leader Agamemnon. Interwoven in the tragic sequence of events are powerfully moving descriptions of the ebb and flow of battle, the besieged city of Ilium, the feud between the gods, and the fate of mortals.       @RageAgainstTheAchaean Pissed. I am so, so very pissed.   First I have to go to this beach. Then I have to kill all these dudes. And NOW – now! This prick stole my biscuit. Who does that? Am I right?   Can’t resolve this problem on my own – calling Mom!   From Twitterature: The World''s Greatest Books in Twenty Tweets or Less', NULL, '2015-07-06', '9780140447941.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9781853262326', 'Hard Times (Wordsworth Classics) (Wordsworth Collection)', 'Charles Dickens', '9781853262326', '1853262323', 'Wordsworth Editions Ltd', 1998, 272, 'Introduction and Notes by Dinny Thorold, University of Westminster Illustrated by F. Walker and Maurice Greiffenhagen Unusually for Dickens, Hard Times is set, not in London, but in the imaginary mid-Victorian Northern industrial town of Coketown with its blackened factories, downtrodden workers and polluted environment. This is the soulless domain of the strict utilitarian Thomas Gradgrind and the heartless factory owner Josiah Bounderby. However human joy is not excluded thanks to ''Mr Sleary''s Horse-Riding'' circus, a gin-soaked and hilarious troupe of open-hearted and affectionate people who act as an antidote to all the drudgery and misery endured by the ordinary citizens of Coketown.', NULL, '2015-07-06', '9781853262326.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9781853260452', 'Robinson Crusoe (Wordsworth Classics) (Wadsworth Collection)', 'Daniel Defoe', '9781853260452', '1853260452', 'Wordsworth Editions Ltd', 1997, 272, 'With an Introduction and Notes by Doreen Roberts, Rutherford College, University of Kent at Canterbury From its first publication in 1719, Robinson Crusoe has been printed in over 700 editions. It has inspired almost every conceivable kind of imitation and variation, and been the subject of plays, opera, cartoons, and computer games. The character of Crusoe has entered the consciousness of each succeeding generation as readers add their own interpretation to the adventures so thrillingly ''recorded'' by Defoe. Praised by eminent figures such as Coleridge, Rousseau and Wordsworth, this perennially popular book was cited by Karl Marx in Das Kapital to illustrate economic theory. However it is readers of all ages over the last 280 years who have given Robinson Crusoe its abiding position as a classic tale of adventure.', NULL, '2015-07-06', '9781853260452.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9781853260209', 'Jane Eyre (Wordsworth Classics) (Wadsworth Collection)', 'Charlotte Bronte', '9781853260209', '1853260207', 'Wordsworth Editions Ltd', 1997, 448, 'Introduction and Notes by Dr Sally Minogue, Canterbury Christ Church University College. Jane Eyre ranks as one of the greatest and most perennially popular works of English fiction. Although the poor but plucky heroine is outwardly of plain appearance, she possesses an indomitable spirit, a sharp wit and great courage. She is forced to battle against the exigencies of a cruel guardian, a harsh employer and a rigid social order. All of which circumscribe her life and position when she becomes governess to the daughter of the mysterious, sardonic and attractive Mr Rochester. However, there is great kindness and warmth in this epic love story, which is set against the magnificent backdrop of the Yorkshire moors.', NULL, '2015-07-06', '9781853260209.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9781853260230', 'Frankenstein (Wordsworth Classics)', 'Mary Wollstonecraft Shelley', '9781853260230', '1853260231', 'Wordsworth Editions Ltd', 1997, 208, 'With an Introduction and Notes by Dr Siv Jansson, University of Greenwich  Begun when the author was only eighteen and conceived from a nightmare, Frankenstein, is the deeply disturbing story of a monstrous creation which has terrified and chilled readers since its first publication in 1818. The novel has thus seared its way into the popular imagination while establishing itself as one of the pioneering works of modern science fiction.', NULL, '2015-07-06', '9781853260230.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9781853260124', 'Oliver Twist (Wordsworth Classics)', 'Charles Dickens', '9781853260124', '1853260126', 'Wordsworth Editions Ltd', 1997, 400, 'Introduction and Notes by Dr Ella Westland, University of Exeter Dickens had already achieved renown with The Pickwick Papers. With Oliver Twist his reputation was enhanced and strengthened. The novel contains many classic Dickensian themes - grinding poverty, desperation, fear, temptation and the eventual triumph of good in the face of great adversity. Oliver Twist features some of the author''s most enduring characters, such as Oliver himself (Who dares to ask for more), the tyrannical Bumble, the diabolical Fagin, the menacing Bill Sykes, Nancy and ''the Artful Dodger''.', NULL, '2015-07-06', '9781853260124.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9780140623338', 'Wuthering Heights', 'Emily Bronte', '9780140623338', '0140623337', 'Penguin Classics', 2007, 288, 'In a house haunted by memories, the past is everywhere ...As darkness falls, a man caught in a snowstorm is forced to shelter at the strange, grim house Wuthering Heights. It is a place he will never forget. There he will come to learn the story of Cathy: How she was forced to choose between her well-meaning husband and the dangerous man she had loved since she was young? How her choice led to betrayal and terrible revenge - and continues to torment those in the present? How love can transgress authority, convention, even death? And how desire can kill?', NULL, '2015-07-06', '9780140623338.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9780743487658', 'Heart of Darkness and the Secret Sharer (Enriched Classics)', 'Joseph Conrad', '9780743487658', '0743487656', 'Simon & Schuster', 2004, 240, 'ENDURING LITERATURE ILLUMINATED BY PRACTICAL SCHOLARSHIP  Two of Joseph Conrad''s most compelling and haunting works, in which the deepest perceptions and desires of the human heart and mind are explored.  EACH ENRICHED CLASSIC EDITION INCLUDES:  • A concise introduction that gives readers important background information  • A chronology of the author''s life and work  • A timeline of significant events that provides the book''s historical context  • An outline of key themes and plot points to help readers form their own interpretations  • Detailed explanatory notes  • Critical analysis, including contemporary and modern perspectives on the work  • Discussion questions to promote lively classroom and book group interaction  • A list of recommended related books and films to broaden the reader''s experience  Enriched Classics offer readers affordable editions of great works of literature enhanced by helpful notes and insightful commentary. The scholarship provided in Enriched Classics enables readers to appreciate, understand, and enjoy the world''s finest books to their full potential.  SERIES EDITED BY CYNTHIA BRANTLEY JOHNSON', NULL, '2015-07-06', '9780743487658.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9780413744906', 'Private Lives (Modern Classics)', 'Noël Coward', '9780413744906', '0413744906', 'Bloomsbury Methuen Drama', 2000, 96, 'One of Coward''s best-loved classics in a single-play editionCoward''s wit and precision as a modern dramatist is nowhere better exemplified than in this classic modern plays from 1930. Elyot Chase and Amanda Prynne (originally played by Gertrude Lawrence and Noël Coward), recently divorced from one another five years previously, arrive coincidentally at the same French hotel. They are honeymooning with their respective new spouses. Encountering one another by chance, each is at once horrified and fascinated by the other. Together they leave for Paris and begin a roundelay of quarrels and love intrigues that culminate in their getting back together.', NULL, '2015-07-06', '9780413744906.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9780435909918', 'Second Class Citizen by Emecheta, Buchi ( Author ) ON Mar-01-1994, Paperback', 'Buchi Emecheta', '9780435909918', '0435909916', 'Pearson Education Limited', 1994, NULL, 'Second Class Citizen by Emecheta, Buchi ( Author ) ON Mar-01-1994, Paperback - Emecheta, Buchi - Pearson Education Limited', NULL, '2015-07-06', '9780435909918.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9781853260919', 'To the Lighthouse (Wordsworth Classics)', 'Virginia Woolf', '9781853260919', '1853260916', 'Wordsworth Editions Ltd', 1999, 176, 'To the Lighthouse is the most autobiographical of Virginia Woolf''s novels. It is based on her own early experiences, and while it touches on childhood and children''s perceptions and desires, it is at its most trenchant when exploring adult relationships, marriage and the changing class-structure in the period spanning the Great War.', NULL, '2015-07-06', '9781853260919.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9781853260063', 'Portrait of the Artist As a Young Man (Wordsworth Classics) (Wadsworth Collection)', 'James Joyce', '9781853260063', '1853260061', 'Wordsworth Editions Ltd', 1997, 272, 'With an Introduction and Notes by Dr. Jacqueline Belanger, University of Cardiff A Portrait of the Artist as a Young Man represents the transitional stage between the realism of Joyce''s Dubliners and the symbolism of Ulysses, and is essential to the understanding of the later work. This novel is a highly autobiographical account of the adolescence of Stephen Dedalus, who reappears in Ulysses, and who comes to realize that before he can become a true artist, he must rid himself of the stultifying effects of the religion, politics and essential bigotry of his background in late 19th century Ireland.', NULL, '2015-07-06', '9781853260063.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9780753810316', 'Astonishing the Gods', 'Ben Okri', '9780753810316', '075381031X', 'Orion Publishing Co', NULL, NULL, 'A modern fable with a magical quality by the Booker prize-winning writer.', NULL, '2015-07-06', '9780753810316.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9781853261923', 'Adam Bede (Wordsworth Classics) (Classics Library (NTC))', 'George Eliot', '9781853261923', '1853261920', 'Wordsworth Editions Ltd', 2000, 528, 'With an Introduction and Notes by Doreen Roberts University of Kent at Canterbury  ''Examine your words well, and you will find that even when you have no motive to be false, it is a very hard thing to say the exact truth, even about your immediate feelings...''  Adam Bede (1859), George Eliot''s first full-length novel, marked the emergence of an artist to rank with Scott and Dickens. Set in the English Midlands of farmers and village craftsmen at the turn of the eighteenth century, the book relates a story of seduction issuing in ''the inward suffering which is the worst form of Nemesis''. But it is also a rich and pioneering record - drawing on intimate knowledge and affectionate memory - of a rural world that we have lost. The movement of the narration between social realism and reflection on its own processes, the exploration of motives, and the constant authorial presence all bespeak an art that strives to connect the fictional with the actual.', NULL, '2015-07-06', '9781853261923.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9780141441160', 'A Passage to India (Penguin Classics)', 'E M Forster', '9780141441160', '014144116X', 'Penguin Books', 2005, 376, 'Exploring issues of colonialism, faith and the limits of comprehension, E.M. Forster''s "A Passage to India" is edited by Oliver Stallybrass, with an introduction by Pankaj Mishra. When Adela Quested and her elderly companion Mrs Moore arrive in the Indian town of Chandrapore, they quickly feel trapped by its insular and prejudiced ''Anglo-Indian'' community. Determined to escape the parochial English enclave and explore the ''real India'', they seek the guidance of the charming and mercurial Dr Aziz, a cultivated Indian Muslim. But a mysterious incident occurs while they are exploring the Marabar caves with Aziz, and the well-respected doctor soon finds himself at the centre of a scandal that rouses violent passions among both the British and their Indian subjects. A masterly portrait of a society in the grip of imperialism, "A Passage to India" compellingly depicts the fate of individuals caught between the great political and cultural conflicts of the modern world. In his introduction, Pankaj Mishra outlines Forster''s complex engagement with Indian society and culture. This edition reproduces the Abinger text and notes, and also includes four of Forster''s essays on India, a chronology and further reading. E. M. Forster (1879-1970) was a noted English author and critic and a member of the Bloomsbury group. His first novel, "Where Angels Fear To Tread" appeared in 1905. "The Longest Journey" appeared in 1907, followed by "A Room With A View" (1908), based partly on the material from extended holidays in Italy with his mother. "Howards End" (1910) was a story that centred on an English country house and dealt with the clash between two families, one interested in art and literature, the other only in business. Maurice was revised several times during his life, and finally published posthumously in 1971. If you enjoyed "A Passage to India", you might like Rudyard Kipling''s "Kim", also available in "Penguin Classics". "His great book...masterly in its presence and its lucidity". (Anita Desai).', NULL, '2015-07-06', '9780141441160.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9780001361287', 'The Hobbit', 'J. R. R. Tolkien', '9780001361287', '0001361287', 'HarperCollins Publishers Canada, Limited', 1999, 10, 'The adventures of Bilbo Baggins and his quest forr stolen treasure have enthralled readers for over sity years.  Now, through John Howe''s magical artwork, Tolkien''s world is bbrought vividly to life in this stunning and sophisticated three dimensional celebration of that famous  jorney.', NULL, '2015-07-06', '9780001361287.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786055943578', 'Dewey', NULL, '9786055943578', '6055943573', 'Pegasus Yayinlari', NULL, NULL, NULL, NULL, '2015-07-06', '9786055943578.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786050913866', 'Bos Koltuk', 'J.K. Rowling', '9786050913866', '6050913862', 'Dogan Kitap', NULL, 592, 'Yuzyilin en buyuk hikâye anlaticisi J.K. Rowling''den... Kucuk bir kasaba hakkinda buyuk bir roman. Barry Fairbrother kirkli yaslarinin basinda beklenmedik bir sekilde hayata gozlerini yumar. Bu ani olum yasadigi kasabanin halki icin buyuk bir sok olacaktir. Arnavutkaldirimli meydani ve eski kilisesiyle Pagford, siradan bir Ingiliz kirsali gibi gorunse de bu tatli goruntusunun ardinda bir savas surmektedir. Zenginler fakirlerle, gencler ebeveynleriyle, kadinlar kocalariyla, ogretmenler ogrencileriyle surekli bir catisma halindedir. Pagford kesinlikle gorundugu gibi bir yer degildir. Belediye Meclisi''nde Barry''den bosalan koltuk, kasabanin gorup gorecegi en buyuk savasin tetikleyicisi olacaktir. Turlu duzenbazliklar ve hirsla suren, herkesin birbirinin foyasini ortaya cikaracagi secim savasinda zafer kimin olacaktir?', NULL, '2015-07-06', '9786050913866.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750815409', 'Ozan Beedle''in Hikayeleri', 'J.K. Rowling', '9789750815409', '9750815408', 'Edition Orient', 2009, NULL, 'Harry Potter serisiyle taninan J. K. Rowling''den yepyeni bir kitap geliyor! Ilk yedi kopyasini Rowling''in el yazisiyla tamamladigi, resimledigi kitabin bu kopyalarindan alti tanesi yazar tarafindan Harry Potter''in yolculugunda kendisine eslik eden alti kisiye hediye edilmis. Sonuncunun geliri de Children''s High Level Group adli hayir kurumuna verilmek uzere acik arttirmaya cikarilmis. Bu kurum cocuk haklari ve zor durumdaki cocuklarin kosullarinin iyilestirilmesi icin calisiyor. Dunyanin her yerinde oldugu gibi Turkiye''de YKY tarafindan yayimlanacak Ozan Beedle''in Hikâyeleri''nden elde edilecek gelir bu kuruma aktarilacak. Serinin son kitabi olan Harry Potter ve Olum Yadigârlari''ni okuyanlarin hatirlayacaklari, kitapta buyuk onem tasiyan, olaylarin aydinlanmasinda kritik bir rol oynayan bir ic kitap Ozan Beedle''in Hikâyeleri. Ozan Beedle''in Hikâyeleri, bes farkli hikâye iceriyor. Bildigimiz masal kaliplarindan ve kliselerinden uzak, mesajlarini Rowling''in alisildik esprili uslubuyla veren, yazarin butun kitaplari gibi sadece cocuklari hedef almayan bir kitap. Harry Potter dunyasinin en sevilen karakterlerinden biri, Hogwarts''in efsanevi muduru Albus Dumbledore''un notlariyla zenginlesen kitap bir masal kitabi olarak, bu dunyayi hic tanimayan kisiler tarafindan buyuk bir zevkle okunabilecegi gibi Harry Potter hayranlarina cok tanidik gelecek karakterler ve hikâyeler iceriyor, akillarindaki bazi sorularin cevaplarini veriyor. Ingilizcesi butun dunyada 4 Aralik 2008''de satisa cikacak olan Ozan Beedle''in Hikâyeleri Ocak ayinin ilk haftalarinda Harry Potter kitaplarinin usta cevirmeni Sevin Okyay''in Turkcesiyle okurlarla bulusacak.', NULL, '2015-07-06', '9789750815409.jpg');
