INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786051114514', 'Hıçkırık', 'Kerime Nadir', '9786051114514', '6051114513', 'Dogan Kitap', 2010, 206, '"Yanlizca para degerlerinin saltanat kurdugu,hukum surdugu,saat basi borsa-doviz haberlerinin pesinde kosuldugu,gonul inceliklerinin git git karardigi,sonup gittigi,simdiki asksiz,duygusuz dunyamizda,leylaklar kusanmis Hickirik herseye karsin hala bir siginak olabilir gibime geldi.Hangimiz,bizi bizden,hayalsiz ve leylaksiz hayatlarimizdan cekip alacak bir "ronams"a ihtiyac duymayiz ki?', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789759044480', 'Tasavvuf: Müslüman Mistiklere Toplu Bakış', 'A.J. Arberry', '9789759044480', '9759044480', 'Ağaç Yayıncılık', 2008, 136, NULL, NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750507144', 'Korkma Ben Varim', 'Murat Mentes', '9789750507144', '9750507142', 'Iletisim Yayincilik', NULL, 424, '"Oldurdugum insanlarla iyi arkadas olacagimizi dusunmusumdur hep." Dublorun Dilemmasi''nin yazarindan komik, hizli, soke edici bir roman daha.Gonul Isleri Bakanligi''nda basin musaviri dovus ustasi Fu. Baskalarinin intikamini alarak hayatini kazanan Gicirbey. Tarih ogretmeni dilber Sebnem Sibumi.Padisah yorganlari saticisi Enver Pasa.Dul gangster Hayati Tehlike.Mr. Spock, Abdulcabbar, Ruhiye Hanim, papagan Huduni, cin Jajha, Atom Bombaciyan, Ucan Kiz, Abidin Dandini, Leyla Kalahari ve digerleri...Korkma Ben Varim''in her sayfasi surprizlerle dolu.Ask, dostluk, intikam, yalnizlik ve siddetin ustaca harmanlandigi roman, olaganustu bir enerji saciyor."Bu kitap karnaval sirasinda basgosteren bir bombardimana benziyor."', NULL, '2015-07-06', '9789750507144.jpg');
