INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789754940619', 'Ilyas Efendi', 'Muzaffer Izgu', '9789754940619', '9754940614', 'Bilgi Yayinevi', 1990, NULL, 'Bir kucucuk kentin, umutlari, olanaklari, dunyasi kucuk yuzlerce memurundan biriydi ''Ilyas Efendi''... Istedigi, devlet kapisindan ekmek yemekti, oldu; bir odacik kiralik bir evdi, edindi. Isi kutsaldi kendince, memur babasindan tek miras kalan da bu duyguydu ona. Isini savsaklamadi, bir gunden bir gune.. Cevresinde sevildi. Ya cevresi? Gununu dolduran is arkadaslari?.. Onlarla paylasti yureginin gizlerini, olmazlarini, olurlarini. Onlar da birer "Ilyas Efendi"ydi gercekte. Tek ayrimlari, olsa olsa ondan bir adim onde oluslariydi, yasta, iste deneyimde... Muzaffer Izgu''nun ustalikla kaleme aldigi bu guzel romani begenerek okuyacaksiniz.', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789754707113', 'Benim adim kirmizi (Cagdas Turkce edebiyat) (Turkish Edition)', 'Orhan Pamuk', '9789754707113', '9754707111', 'Iletisim', NULL, 472, '2006 Nobel Edebiyat Ödüllü Orhan Pamuk 100''ü askin ülkede 46 dilde okunuyor.Orhan Pamuk''un "en renkli ve en iyimser romanim", dedigi "Benim Adim Kirmizi", 1591 yilinda istanbul''da karli dokuz kis gününde geçiyor. iki küçük oglu birbirleriyle sürekli çatisan güzel Seküre, dört yildir savastan dönmeyen kocasinin yerine kendine yeni bir koca, sevgili aramaya baslayinca, o sirada babasinin tek tek eve çagirdigi saray nakkaslarini saklandigi yerden seyreder. Eve gelen usta nakkaslar, babasinin denetimi altinda Osmanli Padisahi''nin gizlice yaptirttigi bir kitap için Frenk etkisi tasiyan tehlikeli resimler yapmaktadirlar. Aralarindan biri öldürülünce, Seküre''ye asik, teyzesinin oglu Kara devreye girer. istanbul''da bir vaizin etrafinda toplanmis, tekkelere karsi bir çevrenin baskilari, pahalilik ve korku hüküm sürerken, geceleri bir kahvede toplanan nakkaslar ve hattatlar sivri dilli bir meddahin anlattigi hikayelerle eglenirler. Herkesin kendi sesiyle konustugu, ölülerin, esyalarin dillendigi, ölüm, sanat, ask, evlilik ve mutluluk üzerine bu kitap, ayni zamanda eski resim sanatinin unutulmus güzelliklerine bir agit."Genç Türk Romancisi Orhan Pamuk, Avrupa''ya roman nasil yazilir, gösteriyor."- Frankfurter Allegemeine, Almanya"Orhan Pamuk''u herkes okumali."- The New Statesman, ?ngiltere', NULL, '2015-07-06', '9789754707113.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789756006054', 'Olasiliksiz', 'Adam Fawer', '9789756006054', '9756006056', 'April Yayincilik', NULL, 475, 'BITIRMEK ICIN YARINI, BASKASINA ANLATMAK ICIN BITIRMEYI BEKLEMEYECEKSINIZ. ''Olasiliksiz demek yetersiz kalacaktir. Insani adeta buyusu altina alan bu hikayede, Adam Fawer, bilim, felsefe, entrika ve maceradan ortaya bir basyapit cikarmis." Clive Cussler ''Ilk cumleden itibaren baglanip kaldim; sayfalari, flos royal tutturmaya calisan bir kumarbazin kartlarini actigi gibi cevirdim. Olasiliksiz, insani dusunduren matematik teorilerini ve maceranin albenisini dahice birlestiren, okura Michael Crichton ve Robert Ludlum''u hatirlatan bir kitap. Gercekten kacirilmamasi gereken bir zevk.'' Ben Mezrich, ''Mekani Batirmak'' ve ''Cirkin Amerikalilar''in yazari ''...hikayenin sonunda, bir yandan sizofreninin gercek nedenlerini dusunurken, bir yandan da tek bir hareketin bir insanin hayatini ne kadar degistirebilecegine sasiriyor olacaksiniz. Olasiliksiz, begeniceginize gozumuz kapali iddiaya girebilecegimiz bir kitap.'' People Bir sabah, yillardir gormediginiz bir arkadasinizi dusunerek uyandiniz. Bir saat sonra, onunla sokakta karsilastiniz. Sizce bu sadece bir tesaduf mu, yoksa cok daha farkli anlami olabilir mi? Siz hic Loto''da buyuk ikramiye kazanmadiniz. Ama birileri kazaniyor. Hem de surekli! Onlar sizden daha mi sanslilar? Sans nedir gercekten? Icinizde butun paranizi kirmiziya yatirmaniz gerektigini soyleyen bir his var. Bu his bir ongoru mudur? Yoksa daha fazlasi mi? Yolda gidiyorsunuz. Kafanizi cevirip yandaki kucuk parka baktiniz ve bir anda bu ani daha once de yasamis oldugunuzu hissettiniz. Evet, Deja Vu. Sizce nedir Deja Vu; Gecmis mi, ruya mi, yoksa gelecegi mi goruyorsunuz? Eger siz de kontrolun kimde oldugunu merak ediyorsaniz, ''Olasiliksiz'' tam size gore bir roman.', NULL, '2015-07-06', '9789756006054.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750804878', 'Son kuşlar', 'Sait Faik, Sait Faik Abasıyanık', '9789750804878', '9750804872', NULL, 2003, 102, NULL, NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789755107677', 'Veba', 'Albert Camus', '9789755107677', '9755107673', 'Can Yayinlari', 1999, NULL, 'Camus adi cogu okur icin Yabanci romaniyla ozdeslesir. Ancak yazarin en onemli yapiti aslinda "Veba"dir. Keskin bir gozlem gucunun destekledigi ari bir bilincle Veba, yalnizca cagimizin degil, tum insanlik tarihinin ortak bir sorununa deginir: Felaketin yazgiya donusmesi. Camus''nun hicbir yapitinda boyle aci bir yazgi, boylesine siirsel bir dille ele alinmamistir. "Veba", insanin ve isigin siiridir. Bu siirde renkler alabildigine koyu, ancak yazarin sesi o denli umut doludur. Beklenmedik bir boyuta ulasan veba salgini tum Oranlilari ilkin umutsuzluga bogar, ardindan Doktor Rieux, Tarron ve Grand''in gosterdikleri dayanisma ornegi, basta yetkililer olmak uzere herkese bir guc ve umut kaynagi olur.', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789752201170', 'Esegin Fikri', 'Ferhan Sensoy', '9789752201170', '9752201172', 'Bilgi Yayinevi', NULL, 159, 'Is kazasi, trafik kazasi gibi cok gorulmeye baslandi gunumuzde ask kazasi! Canim sikilinca bir sigara yakiyorum. Icince oksuruyorum, oksurunce tukuruyorum, tukurunce damagim kuruyor, hemen sarap iciyorum, fakat butun bunlarin bende bir aliskanlik yapmasindan korkuyorum. Bu dusunce bende efkar yapiyor, hemen bir sigara yakiyorum, her efkarlandigimda sigara yakmanin bende bir aliskanlik olmasindan korkuyorum. Ben canim sikilinca sigara iciyorum ve yillardir cok acayip sikiliyor canim. Aptallarin en akilli tarafi, onlar hic vakit kaybetmez, baskalarinin vakit kaybetmesini saglar ve bu konuda haril haril calisirlar! Hic kitap okumayan birinin, hayatinin sonunda kitap sayfasi olan agactan ne farki var, kimildayan canli olarak? Siz siz olun, sinirinize mukayyet olun, sinirinizin kiymetini bilin. Sinirsizlik cok tehlikeli bir boyut. Gencligimde gicik oldugum amcalardanlasmakta miyim?', NULL, '2015-07-06', '9789752201170.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750806452', 'Harry Potter ve Zümrüdüanka Yoldasligi (Harry Potter 5)', 'J. K. Rowling', '9789750806452', '975080645X', 'Yapi Kredi Yayinlari', NULL, 1100, 'Hogwarts Cadilik ve Büyücülük Okulu''ndaki besinci yilinda Harry, hayatini cehenneme çeviren sihirli/sihirsiz pek çok seyle basa çikmak zorunda: Yaz tatilini yanlarinda harcadigi aptal akrabalari; beklenmedik bir anda ve yerde karsisina çikan Ruh Emici''ler; ergenlik çaginin isyanlari, heyecanlari, korkulari; onun gösteris düskünü bir yalanci oldugunu düsünenler; okulun isleyisine burnunu sokmaya çalisan Sihir Bakanligi; gelmis geçmis en berbat Karanlik Sanatlara Karsi Savunma ögretmeni; agir dersler, zor sinavlar, acimasiz cezalar; sürekli yinelenen bir kâbus ve aciyan yara izi; ona en yakin insanlardan birinin ölümü; bes yil gecikmeyle ögrendigi bir gerçek... Dizinin ilk dört kitabinda gözlerimizin önünde adeta etten kemikten bir büyülü dünya kuran J. K. Rowling, yaraticiligiyla yine basrolde: Satirlara ve satir aralarina serpistirilmis zekice ayrintilar, olay örgüsünü daha da zenginlestiriyor ve büyülü dünyaya yeni renkler katiyor. Bu sürükleyici kitabi elinizden birakamayip kalinligiyla ters orantili hizda okuyacak ve tipki Harry gibi bir sonraki okul yilini iple çekerek Hogwarts''tan ayrilacaksiniz.', NULL, '2015-07-06', '9789750806452.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786054322374', 'Sah ve Sultan', 'Iskender Pala', '9786054322374', '6054322370', 'Kapi Yayinlari', NULL, NULL, 'Bir tarihi roman', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753423618', 'Yüksek Topuklar', 'Murathan Mungan', '9789753423618', '9753423616', 'Metis Yayincilik', NULL, 527, 'Bu hacimli kitap orta yasin kiyisindaki yalniz bir kadinin 5 yasinda bir kiz cocuguyla basbasa gecirdigi bes gunde geciyor. Kolay ustesinden gelinmis bir zaman dilimi degil ama. Adeta minyatur bir gunumuz kadin prototipi olan minik Tugde ile yasadiklari roman kahramani acisindan zengin ama istirapli bir deneyime donusuyor ilerleyen sayfalarda. Yuksek Topuklar, Murathan Mungan''dan Istanbul, ozellikle de Beyoglu ekseninde gezinen uzun bir gozlem ve deneyim kilavuzu olarak okunabilir. Bundan birkac yil once yazmaya karar vermistim bu oykuyu. Guzel ve uzun bir oyku olsun istemistim. Her zamanki gibi onca is, onca ugras girdi araya; gundeligin hayhuyunda baska oykuler, baska oykucukler; yalnizca yazilan, yazilmayi bekleyenler degil, yasananlar da gecit vermedi... Sonunda, "Bir gun yazarim, nasil olsa bir gun yazarim," diye beklettiklerimden biri olup cikti bu da... Kimi zaman, yazdigimda, kim bilir nasil muthis bir kitap olacagini dusleyip, heyecanlandiklarimdan biri olarak geliyordu aklima; kimi zaman da yazamadiklarimin yuregimi daraltan agir ceki taslarindan biri olarak... Bu tur "muhasebeler" icinde bulundugum ruh haline gore degisiyordu; belki yazacagi onca seyi ust uste yigip yillar boyu onlarla birlikte gezen butun yazarlarda boyle oluyordur. Artik onlari bilemem. Ama her zaman soylerim, yazip da, duslediklerinizin ne kadarini yazabildiginizi gormektense, "bir gun yazdigimda nasil muthis bir sey olacak kim bilir!" diyerek kendinizi gelecege ertelemeniz daha heyecan vericidir. Bilirsiniz, insanlari heyecanlari yasatir. Buraya kadar soylediklerimden benim bir yazar oldugumu dusunmus olmalisiniz; hayir, degilim, ama oyle zannedilmek hosuma gidiyor. Aslinda yaziya gonul vermis oldugumu, bos zamanlarimda, nasil derler, "kendi capimda" oykuler, oykucukler, cesitli denemeler yazdigimi, ne yazik ki, ancak birkac yakinim biliyor. Onlarin da pek ciddiye aldigini sanmiyorum. Basarili bir grafikerim, isime cok asilmamakla birlikte fena para kazanmiyorum; bunlarin', NULL, '2015-07-06', '9789753423618.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750511189', 'Hikâyem Paramparça', 'Emrah Serbes', '9789750511189', '9750511182', 'Iletisim Yayincilik', NULL, 176, '"Annemin oldugunu anlatma, onun etkisi altinda oldugum icin kendisini sevdigimi dusunmesin." "Tamam Galip." "Karanlikta uyuyamadigim icin gece lambasini acik biraktigimi anlatma, beni ottan boktan korkan biri zannetmesin." "Tamam Galip." "Ilk defa âsik oldugumu anlatma, beni bu konularda tecrubesiz biri zannetmesin." "Tamam Galip." "Gecen sene el frenini cekmeyi unutup Kartal''i boklu dereye yuvarladigimizi anlatma. Malinin kiymetini bilmeyen biri oldugumu dusunmesin." "Tamam Galip." "Babamin orospu cocugu oldugunu anlatma. Onu bizzat ben anlatmak istiyorum." "Tamam Galip." Gecenin ilk musterisi olan, sabahci kahvelerinde, corbacilarda ayilan genc adamlar. Bazen en anlamsiz yuzu yasamanin ve bazen yel degirmenini arayan icli bir hatira. Henuz olmemisler ve olumle tanismamislara yazilmis hikâyeler... Namluya surulmus kufur... Buyumemis bir cocuk... Pati yapan arabalar, yutkuna yutkuna dinlenen sarkilar ve hayattan meseleler. Kutlanan yenilgiler, "hayat kerpicten bir gokdelen sevgili kardesim, yanlis bir parantezde yasiyoruz. Birak konusalim, iki cift laf edelim, yuz yuze bakiyoruz..." Emrah Serbes, hayati kendine katik eden, sokaktan caglayan bir sesle yeraltinin dumanini anlatiyor bize. Bitmez bir ergen ofkesiyle kuyuya dusmus cocuklara sesleniyor. Emrah Serbes''ten parca parca anlar, parca parca anilar, paramparca hikayler...', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753423724', 'Tol', 'Murat Uyurkulak', '9789753423724', '9753423721', 'Metis Yayincilik', NULL, NULL, 'Cozuldun ve utancindan olecek haldesin. Adin, ancak dunyanin yarisi havaya ucarsa temizlenir diye dusunuyorsun. Zaten durmadan bunu planliyorsun. Birbirinden nafile intikam planlariyla oyalaniyorsun. Kafana kursunu sikana kadar da bundan baska bir sey yapacagin yok. Gecen sene aldigin o allahlik Kirikkale tutukluk yapmazsa tabii."', NULL, '2015-07-06', '9789753423724.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753421201', 'Dunyaya Orman Denir', 'Ursula K. Le Guin', '9789753421201', '9753421206', 'Metis Yayincilik', NULL, NULL, 'Agaclarla kardes gibi yasayan ve dusleri en az bizim gundelik yasamimiz kadar gercek olan bir irk, kendini "gercekci" Arz''lilara karsi nasil savunabilir? "Yazmak cogunlukla zor ama keyifli bir istir benim icin; bu oykuyu yazmasi kolaydi ama pek keyifli degildi. Bana hic cenek birakmadi. Ulserli bir patronun sekreterine mektuph yazdirmasi gibi yazdirdi kendini bana. Ben orman ve dus uzerine yazmak istiyordum; yani belirli bir ekolojiyi iceriden bir bakisla betimlemek, biraz da Hadfield''in ve Dement''in uyku duslerinin islevleri ve dusun yararlari uzerine gorusleriyle oynamak istiyordum. Ama patron ekolojik dengenin tahrif edilmesinden ve eduygusal dengenin reddedilmesinden bahsetmek istiyordu. Ahlâk dersi veren oykuleri pek sevmek, cogunlukla iyilik duygusundan yoksun olurlar.Umarim bu oykuoyle degildir. Medem bir kere ahlâk dersi vermek zorunda kaldim, sunu soyleyebilirim bir tek. Don Davidson olmak Raj Lyubov olmaktan daha da aci vericidir."', NULL, '2015-07-06', '9789753421201.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('kiyidaki-degirmen', 'Kıyıdaki Değirmen', 'George Eliot', NULL, NULL, 'Altın Kitaplar Yayınevi', 1970, 623, 'çev. Gönül Suveren', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789752633711', 'Osmanli''yi Yeniden Kesfetmek', 'Ilber Ortayl', '9789752633711', '9752633714', 'Timas Basim', 2006, NULL, '"Turk toplumu yedi asirlik tarihine ilgi duymaya basladi. Bu ilgi, kuru bir hamaset cizgisini gecti, anlasilan toplumsal dusuncenin ve yorumlamalarin tekâmul etmesi dolayisiyla "Osmanli Imparatorlugu nedir? Bu imparatorlugun kurumlari nedir? Yasam sekli nedir? Bizim icin anlami nedir?" gibi sorulara cevap aranmaya baslandi. Ve bu meyanda, calismalar, hazirliklar yapmak ve yaptiklarimizi genis kitleye tanitmak gibi bir ihtiyac hâsil oldu. Suphesiz ki elinizdeki bu kitap da bunlardan birisidir ve o iddiadadir." Ilber Ortayli Gecmisten gelecege tarihî gelismelere isik tutarken, tarihin biraktigi izleri irdeleyen Ilber Ortayli bu sefer okuru Osmanli''yi; padisahlari, saraylari, yonetim sekli, semtleri ve abidevî eserleriyle kisacasi kendine ozgu kimligiyle yeniden kesfetmeye davet ediyor...', NULL, '2015-07-06', '9789752633711.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789752730762', 'Esir Şehrin İnsanları', 'Kemal Tahir', '9789752730762', '9752730760', 'Ithaki Yayinlari', NULL, NULL, '"Esir Sehir Uclemesi" edebiyatimizin guclu ve klasiklesmis ismi Kemal Tahir''in basyapitlarindandir. Her buyuk ve klasik yapit gibi, bir ya da birden cok problematigi mukemmel bir bicimde isleyen bu nehir roman dizisinin ilk kitabi olan "Esir Sehrin Insanlari"nda Kemal Tahir, Mutareke Donemi Osmanli aydininin ve Istanbul''unun destansi direnisinin ve mucadelesinin benzersiz bir fotografini cekmektedir. Kurtulus Savasi oncesinin anlatildigi pekcok roman yazilmistir kuskusuz, ama hicbiri bu denli edebi ve olumsuz olamamistir. "Turkiye''yi, Turkleri sahiden tanimak isteyen yerli yabanci herkes Kemal Tahir''i okumak, anlamak zorundadir."', NULL, '2015-07-06', '9789752730762.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789755710464', 'Frankenstein', 'Mary Shelly', '9789755710464', '9755710469', 'Arion Basim Yayin', 1996, NULL, 'Frankenstein bizlere, bu dunyaya ait olmayan, insanlar tarafindan reddedilip sevgiden yoksun birakilinca siddete sarilan kimsesiz bir varligin portresini sunar. Ancak yaraticisi Dr. Victor Frankenstein, bilimsel kibrinin, Tanri''nin yerine gecme arzusunun, kadinin rolune soyunmak ve canli bir varlik "dogurmak" istemesinin bedelini odeyecektir. Ucube ve yaraticisinin Mont Blanc''in golgesinde karsi karsiya gelmeleri ve kutbun issiz ve vahsi arazilerinde birbirlerini kovalamalari, bir karabasanin sarsici etkisi icinde aktarilir. Mary Shelley Frankenstein''i tamamladiginda hamileydi, daha once bir cocugunu bebek yasta olume teslim etmisti ve yine hastalikli bir bebek olan kucuk ogluna annelik etmekteydi. Shelley, kendi duygularinin derinliklerinden cekip cikardigi bir duyarlikla yorgun Gotik dehsete yepyeni bir soluk kazandirmis, bu surukleyici ve tuyler urpertici klasigi yaratmistir. Bu kitapta yer alan metin, 1818''de yayinlanan orijinal baskiya aittir. Kitapta ayrica, Mary Shelley''nin yasaminin ve zamanin olaylarinin bir kronolojisini, kapsamli bir giris bolumu ve Mary Shelley uzerine yapilmis elestirilerden bir derleme bulacaksiniz.', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9799756870586', 'Olu Canlar', 'Gogol', '9799756870586', NULL, 'Antik Kitap', 2007, 384, 'Usta yazar Gogol, bu eserde, 19. yy Rusyasi''nin curuyen yanlarini gercekci bir uslupla yansitir. Kisa yoldan zengin olma pesine dusmus Cicikov''un amaci, olmus fakat kayitlari henuz nufus kutugunden silinmemis ´can´lari kâgit uzerinde satin almaktir. Cunku zamanin Rusyasi''nda bir insanin itibari ve zenginligi, sahip oldugu canlarla dogru orantilidir. Gogol, duzenbaz Cicikov''u olmus serflerinin belgelerini satin almak uzere koy koy dolastirirken, okuyucuyu da o donem Rusyasi''nin bozuk duzenini uzerinde gezdirir.', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789759917951', 'Kinyas ve Kayra', 'Hakan Gunday', '9789759917951', '9759917955', 'Dogan Kitap', 2012, 576, '"Hic uykum yok. Hic uyuyamiyorum. Domuz gibi iciyorum. Ama gozlerimi kapali bile tutamiyorum. Sabaha bes saat var. Annemi dusunuyorum. Nerededir simdi? Aynada kendime bakiyorum bazen. Ve tek kelime etmesem bile vucudum yasadiklarimi, hayattan ne anladigimi anlatmaya yetiyor. Sag omuzuma kendi cizdigim kelebek, begenmedigim icin uzerine attigim carpi isareti ve altinda ayni kelebegin bir Japon tarafindan cok daha iyi islenmisi. Sol dirsegimin iki parmak yukarisindaki kursun yarasi. Bileklerimdeki otuz dort dikis. Medeniyeti bir aralar, herkes gibi yaladigimi kanitlayan apandisit ameliyatimin izi. Ve sirtimi kaplayan, Tanri''nin yuzu. Bilmiyorum... Hizli yasadim. Ama genc olmekten cok, hizli yaslandim! Ama hayattayim. Kayra, bir gun bana ''Mutsuzluguna hicbir care aramiyorsun'' demisti."', NULL, '2015-07-06', '9789759917951.jpg');
