INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789756249444', 'Klasik Yunan Mitolojisinin En Guzel Efsaneleri 2', 'Gustav Schwab', '9789756249444', '9756249447', 'Ilya Yayinlari', 2004, NULL, 'Gustav Schwab''in bu kitabi kendi turunde yazilmis en onemli ve en kapsamli klasik olarak kabul edilmektedir. Gunumuzde Bati uygarliginin kulturune damgasini vuran Yunan tanri ve kahramanlarina ait efsaneleri cok canli bir anlatimla gunumuze tasir. Birinci bolumde; en eski yunan efsaneleri, "Argonotlar", "Herakles ve Ogullari", "Theseus", "Oidipus" ve "Thebaili Yediler"'' efsaneleri anlatilir. Ikinci bolum; "Troya"ya, ucuncu bolum ise "Son Tantalidler", "Odyseus" ve "Aeneas"a ayrilmistir. Bu eser antik cagin kahramanlarinin degisikliklerle dolu kaderlerini ve can alici, dokunakli maceralarini goz onune sererken gunumuze kadar guzel sanatlarin her dalina ve edebiyata ilham olmus olaylari ve kisileri, heyecan verici bir anlatimla sunmaktadir.', NULL, '2015-07-06', NULL);
