INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789756902165', 'Cesur Yeni Dunya', 'Aldous Huxley', '9789756902165', '9756902167', 'Ithaki Yayinlari', NULL, NULL, 'Cesur Yeni Dunya bizi "Ford''dan sonra 632 yilina" goturur. Bu dunyanin cesur insanlari kapisinda "Cemaat, Ozdeslik, Istikrar" yazan Londra Merkez Kulucka ve Sartlandirma Merkezi''nde uretilirler. Kadinlarin dollenmesi yasak ve ayip oldugu icin, "annelik'' ve ''babalik'' pornografik birer kavram olarak gorulur Toplumsal istikrarin temel guvencesi olan sartlandirma hipnopedya -uykuda egitim- ile saglanir. Hipnopedya sayesinde herkes mutludur; herkes calisir ve herkes eglenir. "Herkes herkes icindir." "Cesur Yeni Dunya"nin onemi yalnizca ardillari icin bir standart olusturmasi ve karamsar bir gelecek tasariminin guclu betimlemesiyle degil, ayni zamanda ''birey yok edilse de suren macerasinin'' saglam bir uslupta anlatilmasiyla da ilgili. Huxley, yapitini utopa geleneginin kuru anlatiminin disina cikarip ''iyi edebiyat'' kategorisine yukseltiyor.', NULL, '2015-07-06', '9789756902165.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753639866', 'O/ Hakkaride Bir Mevsim', 'Ferit Edgu', '9789753639866', '9753639864', 'Yapi Kredi Yayinlari', 2015, NULL, NULL, NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789759915315', 'Siyah Sut', 'Elif Safak', '9789759915315', '9759915316', 'Dogan Kitap', NULL, 303, 'Bu kitap okunur okunmaz unutulmak icin yazildi. Suya yazi yazar gibi... "Siyah Sut" kadinligin, kadinlarin hayatinin kasvetli ve karanlik ama son tahlilde gecici bir donemiyle ilgili. Birdenbire gelen ve geldigi gibi hizla dalgalar halinde cekile cekile giden bir haletiruhiye burada incelenen. Bu haliyle elinizde tuttugunuz kitap bir nevi taniklik. Otobiyografik bir roman. (...) Annelik dunyanin en yasanilasi, en muhtesem lutuflarindan biri; guzel ki hem de nasil. Aldigi tum ovguleri fazlasiyla hak ediyor. Oylesine benzersiz, oylesine kiymetli... ayni zamanda cetrefil, karmasik ve kimi zaman hayli agir. ''Siyah Sut, cesur, sasirtici, tilsimli bir roman: Bunca kotulugun ortasinda, bize umut veriyor Elif Safak, dayanabilmek, direnebilmek ve sonra hayata, bir mucize gibi, yeniden baslayabilmek icin.'' Selim Ileri', NULL, '2015-07-06', '9789759915315.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786051111070', 'Aşk', 'Elif Safak', '9786051111070', '6051111077', 'Dogan Kitap', NULL, 420, 'Ya ortasindasindir ASK''in merkezinde; ya da disindasindir, hasretinde.. Ella Rubinntain (40) Amerikali bir ev kadinidir. Tipik burjuva degerlerinin hâkim oldugu oldukça varlikli bir ailesi, düzenli ve görünüste "sorunsuz" bir evliligi vardir. Üç çocugunu da büyüttükten sonra bir yayinevinde editör-asistani olarak is bulur; görevi A. Z. Zahara adli taninmamis bir yazarin tasavvuf felsefesini konu alan tarihi romanini degerlendirmektir. Ancak hayatinin kritik bir döneminde eline aldigi bu kitap, hiç beklemedigi bir sekilde Ella''yi derinden sarsacak, dünyevi aski kesfetmek adina zorlu ve tehlikeli bir yolculuga çikmasina neden olacaktir. Hayatlarimizin durgun gölünü dalgalandiran tas misali, yüzlesmek zorunda oldugumuz sikintilar, acilar... ve askin pesinde kat etmek zorunda oldugumuz zorlu yollar, ödedigimiz bedeller... Ask... kitap içinde bir kitap, hayatin anlami pesinde bir ask macerasi... Ask... Elif Safak''tan arayisa, gerçege ve kesfetmeye dair bir roman.', NULL, '2015-07-06', '9786051111070.jpg');
