INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786051110363', 'Bab-i Esrar', 'Ahmet Ümit', '9786051110363', '6051110364', 'Edition Orient', NULL, 394, '"Ahmet Ümit''ın son romanı, Bab-ı Esrar... Yaşamı, aşkı ve inancı yeniden düşünmek için... Yedi yüz yıldır çözülemeyen sır; Şems-i Tebrizi cinayeti... Yedi yüz yıldır süren bir sevda; Şems-i Tebrizi ile Mevlânâ Bab-ı Esrar sadece bir gerilim romanı değil, aynı zamanda bir sırlar kitabı. Fantastik öğeleri kullanarak çok katmanlı bir dil yaratan Ahmet Ümit bu yapıtında Mevlevilik temelinde din ve inanç üzerine ilginç sorular soruyor. Din ile aşk arasında, inanç ile sevda arasındaki ilişkiyi bambaşka bir açıdan gözlerimizin önüne seriyor. Dünyayı, yaşamı, inancı ve aşkı, yeniden düşünmemiz, yeniden araştırmamız, yeniden okumamız için... "', NULL, '2015-07-06', '9786051110363.jpg');
