INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789759099718', 'Durdane Hanim', 'Ahmet Mithat Efendi', '9789759099718', '9759099713', 'Iskele Yayincilik', 2005, 208, 'Durdane Hanim', NULL, '2015-07-06', '9789759099718.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753420631', 'Göçmüş Kediler Bahçesi', 'Bilge Karasu', '9789753420631', '9753420633', 'Metis Yayincilik', NULL, NULL, '"Oyun uzerine ne biliyorsam ondan ogrenmistim. Ustam karsimda duruyordu. Ama oyunun oynanmasi uzerine bilgi vermemisti. Satranca cok benzeyen bu oyunda taslarin, yani bizlerin adi, satranctaki gibiydi, kurallar hemen hemen ayniydi. Bir iki noktada satranctan ayriliniyordu. O noktaliri da baskan anlatmisti bu sabah. Ne ki, satranc oynamasini bilip bimedigimi kimse sormamisti. Morlarin bilmesi gereksizdi zaten. Bir zamanlar biraz oynamis oldugum yicin, oyunu bilmiyorum diyerek isin icinden siyrilmaga da kalkismamistim. Oynamak istemistim, basindan beri, onu gordugumden, oyuna katilip katilmayacagimi sorusundan beri...', NULL, '2015-07-06', '9789753420631.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750503221', 'Dublörün Dilemmasi', 'Murat Mentes', '9789750503221', '9750503228', 'Edition Orient Vertrieb', NULL, NULL, NULL, NULL, '2015-07-06', '9789750503221.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750504402', 'Her Temas Iz Birakir', 'Emrah Serbes', '9789750504402', '9750504402', 'Iletisim Yayincilik', NULL, NULL, 'Kizilay, Sakarya Caddesi, SSK Ishani, Dil-Tarih, Atakule, ogrenci evleri... ve Emniyet... Cinayet Masasi. Behzat C., "yeni muktesebata" uyum saglayamamis, lambur lumbur, "disli" bir baskomiser. Muzik dinlemez, polis telsizi dinler. Kitap okumaz, gazeteye spor sayfasindan baslar. Herhangi bir siyasi gorusu yok. "Icimizden birinin" ucuncu sayfa haberlerine yansimis hali gibi, adi bile tam degil. 1. Amator''de duran toplara iyi vuran bir stoperken, topculugu birakip baskalarini tekmelemeye baslamis. Mesela bes lira icin kalbinden adam bicaklayanlari, on uc yasinda kizlara tecavuz eden, namus icin en yakin akrabalarini vuranlari... Kendi adalet anlayisi bakimindan sorun yok; "it ugursuz" kimdir, belli gibi gorunuyor... Ama acaba oyle mi? Behzat C.''yi ve onun adalet duygusunu da rahatsiz eden isler olabiliyor bazen hayatta... At izinin it izine karistigi bir cinayet... Kim, niye oldursun bu kizi? Hem niye bu sekilde? Siyaset karismis desek?.. Garip... Ogrenci âlemine, baska âlemlere, ama asil polis âlemine dikiz atan, entrikasi bereketli bir polisiye...', NULL, '2015-07-06', '9789750504402.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786050915037', 'Kaiken', 'Jean-Christophe Grange', '9786050915037', '6050915032', 'Dogan Kitap', NULL, 384, 'Kaiken''in zamani geldi Dogan gunes karardiginda, Gecmis, ciplak bir kilic gibi keskinlestiginde, Japonya artik bir ani degil, kâbus oldugunda, Kaiken''in zamani gelmis demektir.', NULL, '2015-07-06', '9786050915037.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753426527', 'Hasretinden Prangalar Eskittim', 'Ahmed Arif', '9789753426527', '9753426526', 'Metis Yayincilik', 2013, 184, 'Hasretinden Prangalar Eskittim, ilk kez 1968 yilinda yayimlandi. O tarihten gunumuze defalarca baski yapti. Birbirini takip eden birkac kusak sosyalist ve devrimcinin ellerinde, sozlerinde ve sarkilarindaydi. Bircok kisinin aci tatli hatiralarinda unutulmaz, ozel bir yeri oldu. Ahmed Arif siirleri bizce, hem sairin kendi kusaginin hem de ardindan 68-78 kusaklarinin memleket ve halk sevgisini, isyanci ruhunu ve baskaldiri etigini simgeliyor. Kitabin bu 40. yil ozel basimiyla Ahmed Arif`in dizeleriyle, eski kusaklara bir kirmizi karanfil vermek istedik. Daha da onemlisi, gozlerden silinmeye calisildiklari bu cagda, bu fikirleri ve degerleri genc okurlara tasimak, hatirlatmak istedik. Ahmed Arif (1927-1991) Diyarbakir dogumludur. Ortaogrenimini Afyon Lisesi`nde tamamladi. Ankara Universitesi Dil ve Tarih Cografya Fakultesi`nde felsefe egitimi yaparken Ceza Yasasi`nin 141. ve 142. maddelerine aykiri eylemde bulunma saviyla ilki 1950, ikincisi 1952-53 olmak uzere iki kez tutuklandigindan ogrenimini tamamlama olanagi bulamadi. Cesitli Ankara gazetelerinde calisti. Siirleri 1944-55 arasinda donemin dergilerinde yayimlandi. Ilk ve tek siir kitabi Hasretinden Prangalar Eskittim 1968`de basildi. Gunumuze kadar defalarca baski yapan kitap, basta 68 ve 78 doneminin sosyal muhalefet hareketleri olmak uzere genis bir okur kesimi tarafindan benimsendi ve bir klasik haline geldi.', NULL, '2015-07-06', '9789753426527.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750506765', 'Erken Kaybedenler', 'Emrah Serbes', '9789750506765', '9750506766', 'Iletisim Yayincilik', NULL, 143, 'AnKara polisiyeleriyle tanidigimiz Emrah Serbes, bu defa direksiyonu kiriyor ve edebiyatimizda pek de islenmemis bir baska meseleye el atiyor. Erkek cocuklarin enerjik, huzunlu, alengirli dunyasina giriyoruz... Baba calisiyor, anne ev hanimi, muhafazakârligin kalesi...Isciler, yoksullar, teyzeler, abiler... Kolay aglayan sert adamlar... Tasra seyrekligi, mahallenin kalabaligi... Kiskanc, gururlu, saf ergenler... Emrah Serbes, cabuk ofkelenen, kolay vazgecen, bastan cikmis erkek cocuklari konusturuyor... Kederli, insana dokunan komik hikâyeler bunlar... "Dizinin dizime degisi, Handan''in annesi icin bir kelebegin kanat cirpisiysa benim icin kasirgaydi. Kac sene gecti, hâlâ unutmam, gunde en az bes sefer aklima gelir. Biliyorum bu durumun, kokeni memeden kesildigim gune kadar uzanan psikolojik nedenleri vardir. Ama bir kadini unutulmaz yapan sey, bir vakitler ona duyulan arzunun siddetiyle dogru orantili degil midir? O arzunun kiyisinda, gerceklesme olasiliginin tam yani basinda, sanki arada baska hicbir engel yokmus gibi rahat davranabilmekle, kendini o tatli yanilsamaya kaptirabilmekle dogru orantili degil midir? Bu olgunun da mi sorumlusu benim mutsuz gecen cocuklugum? Cevap? Yok! Kalirsin oyle..." Tasrada ve kâinatta, yapayalniz kalmis erkek cocuklarin hikâyesi... Erken Kaybedenler... Yoldan cikmis bir neslin manifestosu...', NULL, '2015-07-06', '9789750506765.jpg');
