INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750802959', 'Harry Potter Ve Sırlar Odası', 'J.K. Rowling', '9789750802959', '9750802950', 'Milet Publishing Ltd', NULL, NULL, 'Dursley''ler o yaz oylesine cekilmez olmuslardir ki, Harry bir an once okulu Hogwarts''a geri donmek icin can atmaktadir. Esyalarini toplarken ortaya cikan ev cini Dobby ise onu uyarir: Hogwarts''a donerse, bir felaket olacaktir. Olur da: Sirlar Odasi''nin acilmasiyla ortaya cikan karanlik bir guc, Hogwarts''takileri tasa cevirmeye baslar. Harry, hayatini tehlikeye atarak, Oda''nin elli yillik olumcul gizemini cozmeye calisir. Ve gercekten de basina gelmedik felaket kalmaz. Harry Potter''in okuldaki ikinci yilini anlatan Harry Potter ve Sirlar Odasi''nda J.K. Rowling, bildik ogrenci sorunlarini -kiskancliklar, rekabetler, cekingenlikler- yer yer urkutucu, yer yer komik dussel ogelerle ustaca ic ice geciriyor. Dizinin ilk kitabi Harry Potter ve Felsefe Tasi kadar surukleyici olan bu ikinci kitabi heyecandan solugunuzu tutarak okuyacaksiniz.', NULL, '2015-07-06', '9789750802959.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789754702095', 'Tehlikeli Oyunlar', 'Oguz Atay', '9789754702095', '9754702098', 'Iletisim Yayinlari, Istanbul', NULL, 479, 'Kisinin kendiyle savasmasini ve yenmesini, kendini donusturmesini hayati bir sorun olarak algilamaya cagiran, carpici ve sarsici bir roman. Romanin bas kisisi Hikmet Benol, toplumdaki yogun kargasanin temelinde yatan gercekligi arastirirken, gerceklerle ictenlikle ilgilenmenin toplumu yonetenlerce tehlikeli goruldugunu seziyor ve ''oyun oynuyormus gibi'' ilgilenmenin ve yasamanin yollarini arastiriyor. Ve hem ''tehlikeli'' hem de ''oyun''la dolu bir yolda gidebilecegi son noktaya kadar ilerliyor...', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789754700114', 'Tutunamayanlar', 'Oguz Atay', '9789754700114', '9754700117', 'Iletisim Yayinlari', NULL, 736, 'Tutunamayanlar, Türk edebiyatinin en önemli eserlerinden biridir. Berna Moran, Oguz Atay''in bu ilk romanini "hem söyledikleri hem de söyleyis biçimiyle bir baskaldiri" olarak niteler. Moran''a göre "Oguz Atay''in mizah gücü ve duyarliligi ve kullandigi teknik incelikler, Tutunamayanlar''i büyük bir yetenegin ürünü yapmis, eserdeki bu yetkinlik Türk romanini çagdas roman anlayisiyla ayni hizaya getirmis ve ona çok sey kazandirmistir." Küçük burjuva dünyasini ve degerlerini zekice alaya alan Atay, "saldirisi tutunanlarin anlamayacagi, rededecegi türden bir romanla yapar."', NULL, '2015-07-06', '9789754700114.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789752890572', 'Balik Izlerinin Sesi', 'Buket Uzuner', '9789752890572', '9752890571', 'Everest Yayinlari', 1998, NULL, 'Anne tarafindan Afife Jale''ye akraba oluyorum. Babamin kokleri de Piri Reis''in amcasi Kemal Reis''e uzanir, dedim gururla. - Camile ve Kolomb gibi mi yani? dedi sasirarak. - Hic kimse bir baskasina benzemez! diye hircinlastim. - Afife Piri! dedi hayranlikla. - Afife Piri! diye yineledim. - Denizlerin seruvenci ogluyla, sahne isiklarinin cesur, asi kizinin torunusun, muthis... olaganusu... Anlamaliydim... Coktan anlamaliydim...', NULL, '2015-07-06', '9789752890572.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753389365', 'Tasavvuf Psikolojisi', 'Hasan Kayiklik', '9789753389365', '9753389361', 'Akcag Yayinlari', 2009, 240, 'Gunumuzde cagdas insani, materyalizmin ivme kazanmasiyla sekuler gucler tarafindan kusatilmislik ...', NULL, '2015-07-06', '9789753389365.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750807145', 'Ince Memed 1', 'Yasar Kemal', '9789750807145', '9750807146', 'Yapi Kredi Kültür Sanat Yayinc', NULL, 436, 'Otuz iki yillik bir zaman diliminde yazilan Ince Memed dortlusu duzene baskaldiran Memed''in ve insan iliskileri, dogasi ve renkleriyle Cukurova''nin oykusudur. Yasar Kemal''in soyleyisiyle ''icinde baskaldirma kurduysa dogmus'' bir insanin, ''mecbur adam''in romani. Abdi Aga''nin zulmuyle koyunu terk etmek zorunda kalan Memed, Aga''nin yegeniyle evlendirilmek uzere olan Hatce''yi kacirir. Abdi Aga''yi yaralayan, yegenini de olduren Memed eskiya Deli Durdu''ya katilir, ancak kiyiciligina katlanamadigi Deli Durdu''dan iki arkadasiyla birlikte ayrilir. Memed, siradan bir koy cocuguyken, zulmedenler icin eskiyaya, koyluler icinse bir kurtariciya donusur. "Bir yasam bicimini bir halkin portresi olarak boylesine veren bu romandan daha iyisi yazilamazdi." - The New York Times Book Review, (A.B.D.) "Sasirtici, orijinal bir kitap." - Sunday Times, (Ingiltere) "Epik boyutlara ulasan ve muhtesem bir sona ulasmak icin hiz kazanan oykuye kendinizi kaptiriyorsunuz." - Sunday Times, (Ingiltere) ''Yasar Kemal, sasilacak olcude yaratici'' -The Booksell, (Ingiltere) ''Yasar Kemal, karakterlerini unutulmaz, seckin ve gercek hayattan daha da gercekci kilan detay zenginligi ile Rus Edebiyatinin kalitesine ulasiyor.''', NULL, '2015-07-06', '9789750807145.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789756719916', 'Kizil Nehirler', 'Jean-Christophe Grange', '9789756719916', '9756719915', 'Dogan Kitap', NULL, 405, NULL, NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750707810', 'Matilda', 'Roald Dahl', '9789750707810', '9750707818', 'Can Cocuk Yayinlari', NULL, NULL, 'Matilda, kitap okumaya karsi doyulmaz bir istahi olan cok zeki, olaganustu bir kizdir. Uc yasina geldiginde evdeki gazete ve dergileri inceleyerek kendi kendine okumayi ogrenmistir. Dort yasina geldiginde koy kutuphanesindeki tum kitaplari bir cirpida bitirmistir. Anne-babasi Bay ve Bayan Wormwood ise onun ise yaramaz bir bas belasi oldugunu dusunmektedir. Onlarin yalnizca televizyon izlemekle ve insanlari aldatarak para kazanmakla ilgili olduklarini goren Matilda, anne-babasini cezalandirmaya karar verir. Kendisine her kotu davrandiklarinda su ya da bu sekilde buna bir karsilik verecektir. Bu zeki, sevimli kucuk kiz cok gecmeden dogaustu gucleri oldugunu da kesfedecektir. Bu gucler yalnizca evde degil, Matilda ve sinif arkadaslarinin gelmis gecmis en korkunc basogretmen olan Bayan Trunchbull''la basa cikarken de cok isine yarayacaktir.', NULL, '2015-07-06', '9789750707810.jpg');
