INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789754052725', 'Bir pırıltıdır yaşamak', 'İpek Ongun', '9789754052725', '9754052727', NULL, 1996, 303, 'Het leven is glitter. - Etiquette voor jongeren.', NULL, '2015-07-06', '9789754052725.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753420686', 'Narla Incire Gazel', 'Bilge Karasu', '9789753420686', '9753420684', 'Metis Yayincilik', 2006, 132, '"Nar kentinde bir incir buldum Nari da inciri de, ovmek isterim. Anam her kisin en karanlik noktasinda, eve gererken bir nar atardi yere, butun gucuyle; parcalanip iyice dagilsin diye., Evin beti bereketi niyetine... Ardindan hizla supurup silerdi ortalagi. Bir iki gun sonra, nairn patladigi yerden cok uzakta incecik bir citirti duydugum olurdu ayagimin altinada. Ne kadar dagilmissa nar taneleri, o kadar iyiydi. Topladiktan sonra soylerdim Anneme, sevinsin, diye."', NULL, '2015-07-06', '9789753420686.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750805288', 'Orhan Veli Bütün Şiirleri', 'Orhan Veli Kanık', '9789750805288', '9750805283', 'Yapi Kredi Yayinlari', NULL, NULL, 'Orhan Veli: Turk siirinin "zincirkiran"i, "kasketgiydiren"i, "sivillestiren"i, "acikhavaozani" ... "Orhan Veli cok daha ileriye bir adim atti: Siirin kendi oz bir dili, bir vezni olmadigi gibi kendine oz konulari da olmayacagini gosterdi, ahengin, musikinin de siirden kaldirilabilecegini anlatti." -Nurullah Atac "Orhan Veli''nin kavgasi, edebiyatimizin en buyuk kavgasidir, buna inaniyorum. Irmagin yatagini daha dogal bir vadiye indirdi. Siire kasket giydirdi, sivillestirdi onu. Bugunku siir verimleri onun daha verimleridir biraz." -Cemal Sureyya "Her tumce bir yana, acik havanin ozanidir Orhan Veli her anlamda. Caddeler genisledi, kitaplar inceldiyse Calap''in isi degildir bu. Gelecege dogru suren bir simdinin siir etkisi! Yalnizca gam degisikligi de degil, hepten Atonal. Orhan Veli olayi da, olayligini yitirmistir artik. Siiri ise kalmistir gorunuyor, genis acidan bir deyisle." -Ece Ayhan', NULL, '2015-07-06', '9789750805288.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750800665', 'Anayurt Oteli', 'Yusuf Atilgan', '9789750800665', '9750800664', 'Yapi Kredi Yayinlari', 2013, NULL, 'Ne olu, ne sag bir yasamin kahramani Zebercet. Gozunu ilk actigi ve yasadigi Anayurt Oteli''yle ayni kaderi paylasiyor: Birbirine benzeyen gecici iliskilerle gecen gunler, yalniz ve tek basina suruklenen bir hayat. Gecikmeli Ankara treniyle gelen -adini bile bilmedigimiz- kadin otelde bir gece kalir ve Zebercet''in de, Anayurt Oteli''nin de sessiz akip giden gunlerinin icerigi degisir. Kucuk ayrintilarin tekduze sasmazliginda nerdeyse takintilarla suruklenen bir yasamin ofkesi de, caresizligi de buyuk oluyor. Turk edebiyatinin unutulmaz bir tipi ve unutulmaz bir mekani.', NULL, '2015-07-06', '9789750800665.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753318358', 'Yalnizlik Paylasilmaz', 'Ozdemir Asaf', '9789753318358', '9753318359', 'Epsilon Yayinlari', 2006, NULL, 'n/a', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753634564', 'Sevda Sozleri', 'Cemal Sureya', '9789753634564', '9753634560', 'Yapi Kredi Yayinlari', NULL, NULL, 'Cemal Sureya, Cumhuriyet Donemi siirinin en ozel "vitamin"iydi. Lirik, erotik, politik gur bir irmak. Sevda Sozleri bu buyuk ustanin butun siirlerini bir araya getiriyor. Oyle bir butunluk ki bu, sicak, tilsimli ve olumsuz...', NULL, '2015-07-06', '9789753634564.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750505669', 'Son Hafriyat', 'Emrah Serbes', '9789750505669', '9750505662', 'Iletisim Yayincilik', NULL, NULL, 'Behzat C., Cinayet Buro Amirligi''nde baskomiser, hayata karsi islenen suclar uzmani... Basina gelenlerden sonra lanet etmis, cekip gitmisti aslinda. (Dizinin ilk kitabi Her Temas Iz Birakir''i okuyanlar bilir.) Hayir, hâlâ isinin basinda! Ama agzini bicak acmiyor. Tek bir laf cikmiyor agzindan. El isaretleriyle, cehresiyle, suskunluklarla anlatiyor anlatacagini - ve tabii dellenmeleriyle... Bu bir AnKara polisiyesidir... Behzat C. ve ekibi, kotu bir Renault Toros''la Sakarya Caddesi''nden Ayas''a kadar altini ustune getiriyor Ankara''nin. Sadece cinayetciler degil, belediyenin envai cesit birimi de altini ustune getiriyor Ankara''nin. Her yer hafriyat. Kavsak insaatiydi, kabloydu, boruydu, tamiratti... Sadece onlar da degil ama... Kendine ''Red Kit'' diyen bir adam da cukurlar kazip duruyor. Oldurduklerini tabuta koyup gomuyor o cukurlara - gomup polise haber veriyor. Cok acayip, cok da zeki bir adam bu, felegin cemberinden gecmis, icinde intikam acisi... Belli, polisle bir meselesi var. Behzat C. ve ekibi, Ahlak Burosu''na bile nasip olup da hâlâ kendilerine verilmeyen bir Megane''in hayalini kurarak, kotu Renault''yla Ankara''da fink atip Red Kit''i ariyor. Bir AnKara polisiyesi...', NULL, '2015-07-06', '9789750505669.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789758398546', 'Üç Silahşörler', 'Alexandre Dumas', '9789758398546', '9758398547', 'İtalik Yayınları', 2003, 311, NULL, NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750809958', 'Harry Potter 6. Harry Potter ve Melez Prens.. Harry Potter 6 und der Halbblutprinz', 'Joanne K. Rowling', '9789750809958', '9750809955', 'Yapi Kredi Yayinlari', NULL, NULL, 'Harry Potter ve Melez Prens 1 Ekim''de okurla bulusuyor! Dizinin ilk bes kitabinda oldugu gibi, bu kitapta da gecmiste sorulmus pek cok sorunun yanitini veren J. K. Rowling okuyucuyu yeni sorularla, Harry Potter''i da yeni sorunlarla bas basa birakiyor. Buyuculer dunyasinda devam eden kargasa artik Muggle''larin dunyasini da etkilemeye baslamistir. Harry Potter, Hogwarts''taki altinci yilini Feci Yorucu Buyuculuk Sinavlarina hazirlanarak gecirecegini dusunmektedir. Artik Quidditch takiminin da kaptanidir. Ancak Diagon Yolu''ndaki okul alisverisi sirasinda Draco Malfoy''un bir seyler cevirdigini fark eder. Lord Voldemort''un gecmisiyle ilgili pek cok bilinmeyen ortaya cikarken bir yandan da Malfoy''un neyin pesinde oldugunu ogrenmeye calisan Harry''yi yine zor gunler beklemektedir.', NULL, '2015-07-06', '9789750809958.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753420723', 'Ekmek Arasi', 'Charles Bukowski', '9789753420723', '9753420722', 'Metis Yayincilik', 2013, 221, '"Ilgi duymuyordum. Hicbir seye ilgi duymuyordum. Nasil kacabilecegime dair hic fikrim yoktu. Digerleri yasamdan tat aliyorlardi hic olmazsa. Benim anlamadigim bir seyi anlamislardi sanki. Bende bir eksiklik vardi belki de. Mumkundu. Sik sik asagilik duygusuna kapilirdim. Onlar adna uzak olmak istiyordum.Gidecek yerim yoktu ama. Intihar? Tanrim, caba gerektiriyordu. Bes yil uyumak istiyordum ama izin vermezlerdi."', NULL, '2015-07-06', '9789753420723.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9799756083214', 'Âşık Sarıcakız', 'Aysun Çobanoglu', '9799756083214', NULL, 'Urun Yayinlari', 2013, NULL, NULL, NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789757652304', 'Âşık Ali İzzet Özkan', 'İlhan Başgöz', '9789757652304', '975765230X', 'Pan Yayincilik', 1994, 255, 'Telsizler Gibi Felek ile yine arayi actik Her halde sucluyum yolsuzlar gibi Garib bulbul gibi burada kaldim Kimim kimsem yoktur dilsizler gibi Bazi yesil oldum bazi al oldum Bazi zehir oldum bazi bal oldum Soyleye soyleye gayri lal oldum Dahi konusamam dilsizler gibi', NULL, '2015-07-06', '9789757652304.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789759038779', 'Şimdi Avrupa', 'Aziz Nesin', '9789759038779', '9759038773', 'Nesin Yayınevi', 2006, 156, NULL, NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789759038243', 'Hoptirinam', 'Aziz Nesin', '9789759038243', '9759038242', 'Nesin Yayinevi', 2005, 152, '"Enbas"in baskisi arttikca artmis. Bu baski karsisinda bunalmislar. Aralarindan bir bilge cikip soyle demis: - Tarihimizi inceleyelim. Atalarimizin zamanindaki Enbas''lar buyruklarini sertlestirip baskilarini artirdikca, atalarimiz bu haksizliga karsi ne yapiyorlarsa biz de oyle yapalim. Bilgenin ogudunu cok uygun bulmuslar. Tarihlerini incelemisler. Bir de bakmislar, Enbas''lar buyruklarini sertlestirip yumruklarini vurdukca, baskiyi artirdikca, atalari da suratlarini asarlar, somurturlarmis. "Enbas"larin artik dayanilmaz, cekilmez olan baskisini karsi kendi tarihlerinden ders aldiklari icin once sevinmisler. "Bize surat asip somurtmaktan baska yol, yontem yok!" deyip hep birden surat asmaya baslamislar.', NULL, '2015-07-06', '9789759038243.jpg');
