INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789758950218', 'Ansiklopedik Divan Siiri Sözlügü (ciltli)', 'Iskender Pala', '9789758950218', '9758950215', 'Kapi Yayinlari', 2013, NULL, 'Elinizdeki sozlukte divan siiriyle ilgili tabiat, tabiat olaylari, cografya, yerlesim bolgeleri, iklim kusaklari, insanlar ve ozellikleri, kozmik âlem, felek, tip, astronomi, yildiz ilmi, burclar, muneccimlik, falcilik, remil, eski batil ilimler, israiliyat, musiki deyim ve terimleri, makamlar, eski sanat dallari, hattatlik, muzehheplik, mucellitlik, eski hayat sistemi, gunluk olaylar, âdetler, gelenekler, oyunlar, eglence hayati, savas, savas aletleri, savas terim ve deyimleri, bezm ve rezm sistemi, efsanevi ve tarihi kisiler, tasavvuf ve tasavvuf i inanis sistemi, bunlara ait deyim ve terimler, tarikatlar, ozellikleri, efsaneler, kissalar, Yunan mitolojisi, dini terimler ve aliskanliklar, ayetler, hadisler, fikih, tefsir ve dini ilimler ile Islâm dini ve dini hayat vs. bircok konularda aciklanmasi gereken maddeler yer almaktadir. Bunun yaninda aciklanmaya muhtac olan divan siirinin ozunu olusturan beseri veya ilahi anlamdaki platonik ask, âsik, masuk, icki alemleri, sevgilide guzellik unsurlari, bu yolda olusmus mazmunlar, remizler, mefhumlar, unlu ask hikâye kahramanlariyla ilgili imajlar ile mesnevi konulari ve divan siirine ozgu sekiller, turler, sanatlar, vezin ve kâfiye ile nazim ozelliklerine de yer verilmistir. Kisaca, Ansiklopedik Divan Siiri Sozlugu, divan siiriyle ilgili karsilasilabilecek her guclugu yenme gayesiyle kaleme alinmis temel bir kaynak eser niteligindedir.', NULL, '2015-07-06', '9789758950218.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789756355046', 'Turk Dili El Kitabi', 'Nurettin Demir', '9789756355046', '9756355042', 'Grafiker Yayinlari', 2005, 272, 'Grafiker Yayinlarinin "El Kitaplari" dizisi icinde yer alan Turk Dili El Kitabi''nda dil, diller ve Turkce ile ilgili en son bilimsel veriler, anlasilir bir bicimde okuyucuya sunulmaktadir. Turk Dili El Kitabi''nin hazirlanmasi asamasinda ele alinan temel konular; dil nedir, dillerin sinirlari var midir, dil turleri, bazi diller digerlerinden zengin olabilir mi, dili incelemenin yollari, dillerin siniflandirilmasi, Turkce''nin akrabalari, Altay dilleri teorisi, Turk Dunyasi''nin sinirlari, Turkce''nin tarihsel donemleri, Oguzca, Eski Anadolu Turkcesi, Osmanlica ve donemleri, dille ilgili populer tartisma konulari, egitim dili, yabanci dillerin etkisi, Turkce yok olma tehlikesiyle karsi karsiya mi, Turkce''nin sesleri, ekleri, kokleri ve sozdizimi seklinde ozetlenebilir. (Tanitim Yazisindan)', NULL, '2015-07-06', NULL);
