INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789754372366', 'Turk Milli Kulturu', 'Ibrahim Kafesoglu', '9789754372366', '9754372365', 'Otuken Yayinlari', 2000, 454, 'Yazarin kulturumuzle alakali olarak erken bir donemde yazdigi ve kendisinden sonra yapilan calismalara yol gosteren eseridir."Her millet maddî imkânlari ve manevî degerleri ile bir kultur butunudur. Bir millet yasamakta ise, onun bir kulturu olacaktir. Biz de takriben 4000 yillik tarihe sahip Turk milletinin kulturunu arastirdik. Asya bozkirlarinda gerceklestirilen bu kulturu cesitli cepheleri ile belirtmege calistik. Kultur unsurlarinin da zamanin ve cevrenin sartlarina uygun bazi degisiklikler gosterdigi, fakat ana vasiflarini daima korudugu gerceginden hareket ederek yaptigimiz is, butun yonleri ile Turk milletince ortaya konup gelistirilmis kulturun catisini kurmak ve onun yuzyillarca karakterini muhafaza eden ozelliklerini tespit etmek gayretinden ibarettir. (Tanitim Bulteninden)', NULL, '2015-07-06', '9789754372366.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789751606952', 'Eski Türkçenin Grameri', 'Mehmet Akalın', '9789751606952', '9751606950', NULL, 1995, 313, NULL, NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789751028099', 'Turk Edebiyatinda Hikaye ve Roman 2', 'Cevdet Kudret', '9789751028099', '9751028094', 'Inkilap Kitabevi', 2009, 344, '"Monografiden metin yayinina, antolojiden ders kitabina kadar uzanan arastirma ve incelemeleriyle Turk edebiyati icin zengin bir ''basvuru kitapligi'' olusturmustur Cevdet Kudret. Turk Edebiyatinda Hikâye ve Roman bu kitapligin seckin orneklerinden biridir. Kronolojik akisiyla edebiyat tarihi, secmece duzeni ve bol metin ornegiyle antoloji, degerlendirmeleriyle elestiri karakteri gosteren bu uc ciltlik calisma alaninin en guvenilir basvuru kaynaklarindan biri kabul edilmektedir. Turk Edebiyatini Tanzimat''tan 1959''a kadar donem donem ele alan serinin ikinci cildi 1911-1922 arasini kapsiyor. II. Mesrutiyet''ten Cumhuriyet''e kadar suren bu donemin yazarlarini hayati/eserleri/sanati cizgisinde degerlendiren kitap, ilk yayim yilindan bu yana Cevdet Kudret''in en onemli calismalarindan biri olmayi surduruyor."', NULL, '2015-07-06', '9789751028099.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789754707830', 'Alevi ve Bektasi Inanclarinin Islam Oncesi Temelleri', 'Ahmet Yasar Ocak', '9789754707830', '9754707839', 'Iletisim Yayincilik', 2003, NULL, 'Turkler, Turkiye ve Islam ve Turk Sufiligine Bakislar''dan bildigimiz kuramsal bakisi ayrintiya indiren bu usta zanaatkar urunu calisma, "Anadolu heterodoksisi" tarihine degerli bir katki sunuyor. Kitapta, eski Turk inanclarinin, samanizmin, Uzakdogu ve Iran dinlerinin, Hiristiyanligin, Yahudiligin putperestligin Islam oncesi donemde Turk topluluklarini nasil etkiledigi ve Islam sonrasi hangi motifleri miras biraktigi uzerinde duruluyor. Donemler ve dinler boyunca hayat eden kultlere, dogaustu inanislara, sagaltma rituellerine, "hayir" ve "ser" alametlerine vb. dikkat cekiliyor. Sozkonusu motiflerin ve tarihsel mirasin izi, onemli Bektasi menakibnameleri boyunca suruluyor: Haci Bektas-i Veli, Hacim Sultan, Abdal Musa, Kaygusuz Baba, Seyyid Ali Sultan, Sultan Secauddin, Osman Baba menakibnameleri ve Babai hareketinin Menakibname-i Kudsiye''si... Din tarihine sosyal tarihcilik perspektifiyle bakan Ahmet Yasar Ocak, dinsel kullturleri tarihsel ve toplumsal arkaplanlari ve karmasik etkilesimleri icinde tahlil ederek, bu ulkeyi anlamak acisindan vazgecilmez bir pencere aciyor.', NULL, '2015-07-06', '9789754707830.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789754705553', 'Turkiye''de tarihin saptirilmasi surecinde Turk Sufiligine bakislar: Ahmed-i Yesevi, Mevlana Celaleddin-i Rumi, Yunus Emre, Haci Bektas-i ... dizisi) (Turkish Edition)', 'Ahmet Yasar Ocak', '9789754705553', '9754705550', 'Iletisim', 1996, 264, 'Turk Islam''i, yani Turkiye''nin tarihsel, toplumsal ve kulturel gelenegi icinde sekillenmis ozgul bicimiyle Islam, son yillarda hararetli tartismalara konu oluyor. Ozellikle Alevilik, cetin tartismalarin savas alani gorunumunde. Bu tartismalarda, somut tarihsel baglamlari gozetmeyen bir bakisin egemenligi goruluyor. Gerek Alevilik, gerekse Turk Islam''inin simge isimleri, bugunku Kemalist veya "Turk-Islam Sentezci" vs. ideolojik tercihleri dogrultusunda, dumduz bir tarihsel sureklilik kurgusu icinde efsanelestiriliyor. Ahmet Yasar Ocak''in elinizdeki derlemesi, her seyden once somut baglamlari gozeten bir tarihcilik yaklasiminin ornegini veriyor. Derlemedeki makaleler, Turk Islam''inin ve ozellikle heterodoks geleneginin ozgul karakterini tasvir eden onemli katkilar iceriyor. Anadolu tarihsel cografyasinda ortodoks ve heterodoks Islam kulturleri arasindaki etkilesimin boyutlari da bu cercevede dikkatimize sunuluyor. Heterodoks Halk Islami''nin farkli kulturleri bagdastirici ozelligini, tasavvufi-mistik karakterinin baskinligini ve mehdici niteligini sergileyen Ahmet Yasar Ocak, Turk Islam''inin dort onemli kisiligini ozellikle ele aliyor: Ahmet-i Yesevi, Mevlana Celaleddin-i Rumi, Yunus Emre, Haci Bektas-i Veli.', NULL, '2015-07-06', '9789754705553.jpg');
