INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789755743974', 'Sufi ve Siir', 'Mahmut Erol Kilic', '9789755743974', '9755743979', 'Insan Yayinlari', 2004, 208, '"Butun sairler siir soylemek hususunda soz meclisinde (Elest Bezmi) bir kadehten sarhos oldular. Lakin bazilarinin sarabina sakinin nazarinin tesiri de karisti. Ma''na aleminin dili ile konusan bu sairlerin agizlari, siir soyledikleri zaman, suret alemine karsi kapalidir. Bunlar hakikat denizine ag atmis olgunluk deryasinin dalgiclaridir. Sen bunlari oteki zumre ile bir tutma, zira bunlarin siirlerinde sairlikten baska senin anlamadigin bir sey daha vardir."', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753380416', 'Eski Türk Edebiyati Tarihi', 'Mine Mengi', '9789753380416', '9753380410', 'Akcag Yayinlari', 2004, NULL, 'Eski Turk Edebiyati TarihiEdebiyat Tarihi - Metinler', NULL, '2015-07-06', '9789753380416.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9780521614030', 'Advanced Grammar in Use With CD ROM', 'Martin Hewings', '9780521614030', '0521614031', 'Cambridge University Press', 2005, 304, 'Advanced Grammar in Use Second edition is a fully updated version of the highly successful grammar title. This new revised edition focuses specifically on the complexities of grammatical choices that advanced students need to appreciate. It also includes a comprehensive Basic Grammar Reference so students can easily review their understanding of language areas they have previously studied.    This edition, with answers and CD-ROM, is ideal for self-study. The CD-ROM includes hundreds of interactive exercises to reinforce the language learned in the book.', NULL, '2015-07-06', '9780521614030.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9780393925326', 'The Norton Anthology of English Literature, Volume 2: The Romantic Period through the Twentieth Century (Norton Anthology of English Literature)', NULL, '9780393925326', '0393925323', 'W. W. Norton & Company', 2006, 3072, 'Read by millions of students over seven editions, The Norton Anthology of English Literature remains the most trusted undergraduate survey of English literature available and one of the most successful college texts ever published.Firmly grounded by the hallmark strengths of all Norton Anthologies—thorough and helpful introductory matter, judicious annotation, complete texts wherever possible—The Norton Anthology of English Literature has been revitalized in this Eighth Edition through the collaboration between six new editors and six seasoned ones. Under the direction of Stephen Greenblatt, General Editor, the editors have reconsidered all aspects of the anthology to make it an even better teaching tool.', NULL, '2015-07-06', '9780393925326.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9780393925319', 'The Norton Anthology of English Literature, Volumes A-C: The Middle Ages through the Restoration and the Eighteenth Century, 8th Edition [Paperback]', NULL, '9780393925319', '0393925315', 'Norton & Company', NULL, NULL, NULL, NULL, '2015-07-06', '9780393925319.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9781853268953', 'The Complete Works of William Shakespeare (Wordsworth Royals Series)', 'William Shakespeare', '9781853268953', '185326895X', 'Wordsworth Editions Ltd', 1997, 1280, 'William Shakespeare (1564-1616) is acknowledged as the greatest dramatist of all time. He excels in plot, poetry and wit, and his talent encompasses the great tragedies of Hamlet, King Lear, Othello and Macbeth as well as the moving history plays and the comedies such as A Midsummer Night''s Dream, The Taming of the Shrew and As You Like It with their magical combination of humour, ribaldry and tenderness. This volume is a reprint of the Shakespeare Head Press edition, and it presents all the plays in chronological order in which they were written. It also includes Shakespeare''s Sonnets, as well as his longer poems Venus and Adonis and The Rape of Lucrece.', NULL, '2015-07-06', '9781853268953.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750806643', 'Ingiliz Edebiyati Tarihi', 'Mina Urgan', '9789750806643', '9750806646', 'Yapi Kredi Yayinlari', 2013, NULL, 'Ingiliz edebiyati tarihini on doneme ayirabiliriz. Gerci bir edebiyat doneminin tam hangi tarihle basladigini, tam hangi tarihte sona erdigini saptamanin yolu yoktur, ama kimi caglarda edebiyat alaninda belirli degisiklikler oldugu da yadsinamaz. 1) Eski Ingilizce donemi sozlu edebiyatin yazili edebiyata gecmesiyle birlikte asagi yukari VII. yuzyilda baslar ve Ingiliz tarihinde bir donum noktasi olan Norman istilasiyla (1066) XI. yuzyilin ortalarina dogru biter. 2) Orta ingilizce donemi, tum Ortacagi kapsayarak XV. yuzyila kadar surer. 3) Ronesans ya da Elizabeth cagi, 1558 ile 1603 arasinda hukum suren Kralice Elizabeth''ten adini alir. Elizabeth''in olumu uzerine Iskocya Krali James tahta ciktgi ve James''in Latince adi Jacobus oldugu icin, Elizabeth caginin son kirk yilina Jacobean cag da denilir. Bu donem, 1642''de Oliver Cromwell''in onderliginde Puritan mezhebindekilerin iktidari ele alarak Commonwealth''i, yani Cumhuriyeti kurmalariyla sona erer. 4) Commonwealth donemi, 1642 ile 1660 yillari arasindaki donemi kapsar. 5) Restorasyon donemi, Cumhuriyetcilerin idam ettikleri Birinci Charles''in oglu ikinci Charles''in tahta oturmasiyla, yani monarsinin restorasyonuyla baslar ve XVIII. yuzyilin baslangicina kadar surer. 6) Neo-Klasik Cag, XVIII. yuzyilin baslangicindan asagi yukari1770 yillarina degin surer. Kralice Anne 1702 ile 1714 yillari arasinda hukum surduigu icin, bu donemin baslangicina Kralice Anne Cagi da denilir. Roma Imparatoru Augustus''un saltanati sirasinda Latin edebiyatinini en unlu kisileri yasadigi ve onlari ornek alan Ingiliz sairleri ve yazarlari kendilerini roma''nin klasik yazarlari kadar onemli sayarak, "Augustan" sifatini benimsediklerinden, bu donemin baska bir adi da Augustan cagidir. 7) XVIII. yuzyilin son otuz yilini kapsayan ve Romantik akimi hazirlayan Pre-Romantik Cagi, Romantizmle birlikte ele almak daha yerinde olur. 8) Romantik Cag 1798''de Wordsworth ile Coleridge''in The Lyrical Ballads''i yayimlamalariyla baslar', NULL, '2015-07-06', '9789750806643.jpg');
