INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786056297649', 'Selcuk Erdem- 4', 'Selcuk Erdem', '9786056297649', '6056297640', 'Getto Basin Yayin', 2012, 128, 'Selcuk Erdem''in sevilen karikaturlerinden olusan tamami renkli yeni karikatur albumu.', NULL, '2015-07-06', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9784883196036', 'Minna No Nihongo: Beginner 1, 2nd Edition', NULL, '9784883196036', '4883196038', '3A Corporation', 2012, 249, 'Since it was first published in 1998, Beginner Japanese has been a staple of Japanese language learning. In this second edition, the vocabulary has been updated accompanied by illustrations that help structure learning. The CD offers supplementary exercises and conversation techniques.', NULL, '2015-07-07', '9784883196036.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789754032604', 'Yunan ve Roma Mitolojisi', 'Colette Estin', '9789754032604', '9754032602', 'Tubitak Yayinlari', 2013, 254, 'Doga olaylariyla ve insanlik tarihiyle ilgili hayal urunu oykulerin toplami olan mitoloji aslinda, tipki bilim gibi, insanin evreni ve dunyayi anlama, aciklama cabasinin bir urunu... Yunan ve Roma Mitolojisi, her seyi anlamaya calisan insanoglunun yaraticiliginin kaynaklarini gozler onune seriyor; ilkcagin iki onemli uygarliginin ayrintili bir resmini ciziyor.', NULL, '2015-07-07', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789756249437', 'Klasik Yunan Mitolojisinin En Guzel Efsaneleri 1', 'DEVRIM DOGAN YÜZER', '9789756249437', '9756249439', 'Ilya Yayinlari', NULL, NULL, 'Gustav Schwab''in bu kitabi kendi turunde yazilmis en onemli ve en kapsamli klasik olarak kabul edilmektedir. Gunumuzde Bati uygarliginin kulturune damgasini vuran Yunan tanri ve kahramanlarina ait efsaneleri cok canli bir anlatimla gunumuze tasir. Birinci bolumde; en eski yunan efsaneleri, "Argonotlar", "Herakles ve Ogullari", "Theseus", "Oidipus" ve "Thebaili Yediler"'' efsaneleri anlatilir. Ikinci bolum; "Troya"ya, ucuncu bolum ise "Son Tantalidler", "Odyseus" ve "Aeneas"a ayrilmistir. Bu eser antik cagin kahramanlarinin degisikliklerle dolu kaderlerini ve can alici, dokunakli maceralarini goz onune sererken gunumuze kadar guzel sanatlarin her dalina ve edebiyata ilham olmus olaylari ve kisileri, heyecan verici bir anlatimla sunmaktadir.', NULL, '2015-07-07', NULL);
