INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786051414898', 'Agir Roman', 'Metin Kacan', '9786051414898', '6051414894', 'Everest Yayinlari', NULL, 126, 'Gunes buluttan siyrilirken Kolera''nin âlemci kadinlari bir omuz darbesinde yikilacakmis gibi duran evlerinin onunde oto tamircileriyle, marangozlarla, tornacilarla aslanlar gibi muhabbete koyuldular. Bir yandan da kaynak yaparken elleri titreyen ustalara esrari daha kallavi icmeleri icin zivana hazirlamaya basladilar. Koylu kadinlar, kocalarinin mahalle hakkinda anlattiklari korku hikâyelerinden tirstiklarindan mahkûmlar gibi camdan bakiyorlardi.', NULL, '2015-07-07', '9786051414898.jpg');
