INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786055656133', 'Yeraltindan Notlar', 'Fyodor Mihailovic Dostoyevski', '9786055656133', '6055656132', 'Antik Kitap', 2009, 142, 'Yer altindan Notlar, Dostoyevski''nin var olus hakkindaki dusunce ve imgelemini en net olarak ortaya koydugu eserdir. Bircok Batili dusunuru varolus felsefesi uzerine dusunmeye itmis, bu anlamda etkilemis bir klasiktir. Yazar, sectigi karakterlerle aci kavramina dayali psikolojik tahlillerde ve cozumlemelerde bulunur. Kitapta, Dostoyevski kendi ic dunyasina net bir aynadan bakmis ve o aynada gorduklerini oldugu gibi yansitmistir. Yerin altinda akil-eylem-erdem iliskisini sorgulayan bir insan icin yerin ustunde, yani modern dunyada gezinen adimlar ne ifade eder? Modern dunyanin dayatmalarina karsi kisinin yalnizligi bilincli bir tercih mi yoksa bir yenilgi midir? Ya da gercekten yerin altinda olan kimdir? Gercek dunyadan kendini soyutlamis bir kisinin ic catismalarini ve hezeyanlarini konu alan Yer altindan Notlar''da Dostoyevski, bu sorulari cevaplayarak varolusun temellerine iner ve bireye yonelik psikososyal tahlillerde bulunur. Dostoyevski okumalarinin olmazsa olmazlarindan kabul edilen bu cok onemli romanda yazarin daha sonra yazdigi tum buyuk romanlarin ipuclarini bulacaksiniz. "Sevgili okuyucularim, yemin ederim, her seyin tam anlamiyla farkinda olmak bir hastaliktir."', NULL, '2015-08-06', NULL);
