INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786054173075', 'Aman Ne Komik', 'Emrah Ablak', '9786054173075', '6054173073', 'Murekkep Basim Yayin', 2009, 192, 'Uykusuz Dergisi Cizerleri Olan Emrah Ablak''in 2 Kitabi', 'Not begun', '2015-08-06', '9786054173075.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786054173679', 'Benim De Söyleyeceklerim Var! (Üç)', 'Umut Sarikaya', '9786054173679', '6054173677', 'Murekkep Basim Yayin', NULL, 234, 'Icine kapanik ve karamsar bir yazara yakismayacak derecede iyi yuzerim. Edebiyat dunyasi olarak Sariyer sahiline insek, diger yazarlar miy miy oturup etrafa utangac gozlerle bakarken ben agzimda sigara ile havada takla atip suya dalarim yada kosarken birden havada doner hazirolda asker selami vererek kaybolurum derin mavilikte. Yuzeye cikinca dalarken agzimin icine hapsettigim sigarami bir dil hareketi ile tekrar cikarir, sahilde duran Turk Edebiyati''nin saskin bakislari esliginde icmeye devam ederek yuzerim. Sonra cikar banktaki ayakkabimin, corabimin, kotumun yanina oturmus sairleri, yazarlari kaldirip banka boylu boyunca uzanir oyle yaparim betimlemelerimi, sosyal tespitlerimi; anlatirim insan hikayelerini... Benim icin yazarlik ayri, sahiller iti olmak ayridir. Bundan ne utanirim nede gocunurum cunku sahilde buyudum ben.', NULL, '2015-08-06', '9786054173679.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786054173167', 'Benim De Söyleyeceklerim Var', 'Umut Sarikaya', '9786054173167', '6054173162', 'Murekkep Basim Yayin', NULL, NULL, 'Bir omur ailemle yasamak... Dusuncesi bile korkunc geliyordu. Her gun bu evde bir izdirap gibiyken, bir omur gecirmek, yavas yavas onlara benzemek. Ben aksam "televizyon karsisinda koltukta uyuyacak adam degilim" diyordum kendi kendime. Kimse inanmazsa inanmasin ben sehir disindaki bir universiteyi kazanacak, bu evden de bu mahalleden de bu sehirden de kurtulacaktim. Her gece yatarken hayaller kuruyordum. Ilk yil yurtta kalirdim, sonra bi eve cikardim. Arkadaslarim gelirdi eve. Cikip sabaha kadar sokaklarda gezerdik... Daha once soyledigim gibi o yillarda aklim az calistigi icin sadece bu iki seyi hayal edebildim eve cikinca; "arkadaslarim gelir, gece sokakta gezeriz." Ama bu kadarini hayal edebilmek bile guzeldi be. Bu dusunceler icerisinde benden beklenmeyecek ustun bir calisma disipliniyle kendimi derslere verdim. Surekli test cozuyor, bu buyuk maratonda diger ogrencilerle aramdaki farki kapatmaya calisiyordum. Annem babam gibi kanepede televizyon karsisinda uyumamak icin, onlara benzememek icin calisiyordum. Artik nasil gaza geldiysem oyle hazirlanmisim ki sinava butun sehir disi tercihlerimi gecip cok az sayida yazdigim Istanbul ici tercihlerimden birini kazandim. Hem de eve cok yakin bir universiteyi... Universiteyi kazandigim gun yikilmistim.', NULL, '2015-08-06', '9786054173167.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786055162597', 'Bin Yillik Hemsehri', 'Halil Babilli', '9786055162597', '6055162598', 'April Yayincilik', 2015, 176, NULL, 'Completed', '2015-11-15', '9786055162597.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789753428590', 'Askin Cep Defteri', 'Murathan Mungan', '9789753428590', '9753428596', 'Metis Yayincilik', 2012, 151, 'Mungan''in aski, ayaklari yere basar bir bicimde ele aldigi son kitabi... Murathan Mungan''in yeni kitabi cok ilgi gorecek. "Yazinca da Gecmiyor", "Kedi Kapisi", "Fal Metinleri", "Bende Kalanlar" ve "Askin Cep Defteri" baslikli bes bolumden olusan ve bilinen edebi turlerden birine kolay dahil edilemeyecek olan kitapta siir, oyku, metin ve aforizmalar yer aliyor. Bir deftere yazilabilecek seyler... Ask her zaman ardinda okunacak bir seyler birakir.', NULL, '2016-11-13', '9789753428590.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750520976', 'Muptezeller', 'Emrah Serbes', '9789750520976', '9750520971', 'Iletisim Publishing', 2016, 163, NULL, NULL, '2016-11-13', '9789750520976.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786054173648', 'Ben', 'Alpay Erdem', '9786054173648', '6054173642', 'Murekkep Basim Yayin', 2012, 250, 'Nerede bir, tutmak istedigi evin onunde emlakciyi beklerken kaldirima oturan bir insan var, kim ne derse desin, orada, cok ama cok guzel bir insan var. Onun saclari hafiften ibibik, bacaklari boyuna oranla inceden kisa. Hayatta da cok az seyden korkarim, bar ortamina dans ederek ve o anda calan ingilizce sarkiya yuzelli kiloluk agziyla gurultulu bir sekilde eslik ederek giren teyzeden korktugum kadar. Izmir''de gordum, degil bardan, Alsancak''tan kactim. Atladim denize, Karsiyaka''dan ciktim. Bir isligima bakar diye bir sey var ama gercekten. Ben cocukken, Galataspor''da futbol oynarken Orhan diye bir golcumuz vardi. Uskudar''da bir cocuk yurdunda kaliyordu.Yurdun krali gibi bir seydi. Bir islik caliyordu, bin tane cocuk kosa kosa Orhan''in yanina geliyordu. Isligi duysunlar yeter ki. Resmen ordusu vardi. Bu orduya istedigi her seyi yaptirabiliyordu. Ustelik de Orhan yasca buyuk de degildi herkesten. Ama oyle bir karizma varmis demek ki, bir isligina baktiriyordu. Ustelik de hayatimda gordugum en iyi golcuydu. Gol atmak icin dogmustu. Hayatim boyunca Orhan kadar siradisi bir karakter daha gormedim.Ve tabii sonra imkansizliklar, harcanan yetenek, yok olan, sirra kadem basan bir Orhan.', NULL, '2016-11-13', '9786054173648.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786054702220', 'Yurt Gezileri', 'Aziz Nesin', '9786054702220', '605470222X', 'Nesin Yayinevi', 2013, NULL, 'Anadolu "Konfor Palas''larla dolu. Yollarin uzerinde Konfor palas yazili, oklu levhalar var. Bu Konfor Palaslarda hela bile yok, gerisini siz dusunun. Helalar yapilardan ayri, uzakta, bir koca aralik, bir pis cukur... Konfordan Palastan asagisi kurtarmiyor. Palaspamdirasin adini Konfor Palas koymuslar. Adi degisti mi, her sey degisir bellemisiz. Baksaniza, bize demokrasinin adindan bir sey var mi? Disaridan bak, Konfor Palas. Ici palaspandiras... Disindan bak, demokrasi. Disi seni yakar, ici beni. (Tanitim Bulteninden)', NULL, '2016-11-13', '9786054702220.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786054883271', 'Okuma Güncesi', 'Aziz Nesin', '9786054883271', '6054883275', 'Nesin Yayinevi', 2014, 704, '704 pages.', NULL, '2016-11-13', '9786054883271.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786055162443', 'Bakele', 'Sezgin Kaymaz', '9786055162443', '605516244X', 'April Yayincilik', 2015, NULL, 'Sahneler ve mekanlar, haller ve duygular, insanlar ve dil... Yumruk gibi hikayeler en korunakli bolgelere iniyor, savunmasiz karanliklarda art arda simsekler cakiyor. Sezgin Kaymaz gucunu nereden aliyorsa orayi guclendiriyor okuyan ''Iyi ki Turkce biliyorum'' diye sukrediyor. Agrilari hortlatan ask, tasma takip ucralara kapatilan vicdan, neyin fisildadigi sir, kum tasinda gizli sans... Careyi uzayda arayanlar, ozru kabahatinden buyuk olanlar, kucuk bir ekte sakli hayatlar, yuz bin sene beklenenler...Zitliklarin dengesi korkusuzca kurcalaniyor, gozyaslari ve kahkahalar esliginde samimi ve sahi bir seruven basliyor. Sezgin Kaymaz, hikayelerin kahramani yaptigi okura sesleniyor: Bakele! (Tanitim Bulteninden)', NULL, '2016-11-13', '9786055162443.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9799757904129', 'Afitap''in Kocasi Istanbul', 'Ferhan Sensoy', '9799757904129', NULL, 'Ortaoyuncular Yayinlari', 2006, NULL, 'cok keldir bir cam agaci hem Ince hem uzun hem sanki dali yok gibi iki savruk dalcik garipce koke yakin tepesi acilmis belli yasli ve politikaci bir dik durus ama yapay biliyorum uflesem sonecek mangal yurekler afitap oyle bir cinar ki binyillardir yasiyor koylerin ortasinda feodal yesererek', NULL, '2016-11-13', NULL);
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789757904045', 'Kazanci Yokusu', 'Ferhan Sensoy', '9789757904045', '975790404X', 'Ferhan Sensoy Yayinlari', 2000, NULL, 'Je M''en Fiche Bilader''den, Haneler''den, kabareci yeteneklerini sevgi ile izledigim Ferhan Sensoy''un taze, sicak, halkci bir mizahi var. Yazgidaslari imiscesine yansittigi Kazanci Yokusu''nun insanciklarini da bu kulfetsiz anlatisi icinde bizlere sevdiriyor. Bu insanciklar nasil ezildiklerinin tortusunu gunluk yasam sevinci icinde unutuyorlarsa, yazar da sanki onlardan biriymis gibi toplumsal ukalaliklardan, yazarca bilgicliklere yeltenmeden anlatisinin tadini cikara cikara onlara ayna tutuyor. Sade onlari konusturdugu diyalgolarr degil, benzetileri ve yorumlari bile argo. Oylesine onlardan. Yazimi bile onlarinki gibi yanlis kullaniyor. Bence uslubunu sevimli yapan da bu... Ben Ferhan Sensoy''un Kazanci Yokusu''nu okurken zaman zaman Celine''i ya da San Antonio''yu okurken aldigim tada benzer haz duydum. Zaman zaman da Adnan Veli''nin Mapushane Cesmesi''ndeki unutulmaz basarisini ansidim. Haldun Taner', NULL, '2016-11-13', NULL);
