INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789751036797', 'Yeni Baslayanlar Icin Can Yilmaz - Klise Hayatlar Matbaasi', 'Can Yilmaz', '9789751036797', '9751036798', 'Inkilap Kitabevi', 2016, 240, 'Kitabini okuyun siz de seveceksiniz. Eline saglik Can Hoca, yine 1-0 ondesin... Benim kitabim bile yok... Yaptin yine numarani... Seni seven kardesin unlu komedyen, CEM YILMAZ', NULL, '2016-11-13', '9789751036797.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789750512018', 'Peri Gazozu', 'Ercan Kesal', '9789750512018', '9750512014', 'Iletisim Yayincilik', NULL, 180, '"Vicdanimiz kuruyor. Babalarini erken kaybetmis yetim cocuklarin masum baslarini koyacaklari gogusler coktan coktu, farkinda misiniz? Gogus coktukce zulum tepemizde kaliyor. Kavisli ve dolasik gecmisimizse, bozuk duzenimizin telleri olmus. Duydugunuz sesler bu yuzden icli ve bu kadar derinden geliyor. Simdi bir turlu sigamayip, delice bir kavgaya tutustugumuz, adina Anadolu denen su kadim topraklarda, binlerce yil once hukum surmus, bir Hitit kralinin ogullarina biraktigi vasiyete bakin isterseniz: ''Oldugumde beni, usulunce yikayin, gogsunuze yaslayin ve topraga birakin.'' Bu kadar." Hayatin en yalin ve en efsunlu meseleleri, olum ve yasam, annebaba-cocuk arasindaki zor muhabbet, buyumek ve yaslanmak uzerine... Vefali bir ogulun gozuyle. Bilhassa olumun, olumle basetmenin olaganustulugu ve olaganligi uzerine..."Alismaya" direnen bir hekimin gozuyle. Tasranin sicak kucagi ve serin kasveti uzerine... Orayi hem icinden hem disindan bilen bir evladinin gozuyle. Turkiye''nin ipin ucundaki yakin tarihinin golgesi... Kalbi avucunda birinin gozuyle. Ercan Kesal''dan, aynanin kenarindaki fotograflar misali hayat parcalari, sohbet makaminda insan hikâyeleri. (Tanitim Bulteninden)', NULL, '2016-11-13', '9789750512018.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786051113869', 'Sahilde Kafka', 'Haruki Murakami', '9786051113869', '605111386X', 'Dogan Kitap', NULL, NULL, 'Kafka Tamura on bes yasina girdigi gun evden kacar. Uzun zamandir planladigi bu kacisin nedeni babasinin yillar once dile getirdigi ugursuz kehanettir. Ama babasinin bir duzenek gibi icine yerlestirdigi kehanet golge gibipesindedir Kafka ilk kez aski ve tutkuyu yasarken gizemli bir cinayetle kehanetin ve kaderinin dugumleri cozulmeye baslar. Sahilde Kafka, XXI. yuzyil edebiyatina damgasini vuran, kitaplari bagimlilik yaratan kult yazar Haruki Murakamiden, hayatin yavan gercekligine karsi buyulu bir dunyanin kapilarini acan bir roman.', NULL, '2016-11-13', '9786051113869.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789757904137', 'Baskaldiran Kursun Kalem', 'Ferhan Sensoy', '9789757904137', '9757904139', 'Ortaoyuncular Yayinlari', 2012, 540, 'Bir irmak kiyisinda dogdum ben Bu yuzden Bir irmak romanidir bu ozgecmissel Hem el yazmasi Elle tutulan Elde var ikinci cilt Sapini gulle donattigim kalem Baskaldiriyor Kursun olarak Daglardan geliyor irmak', NULL, '2016-11-13', '9789757904137.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9789944315111', 'Tanrı Yanılgısı', 'Richard Dawkins', '9789944315111', '9944315117', 'Kuzey Yayinlari', NULL, 400, 'New York Times Bestseller Uluslararasi Bestseller "Herkesin okumasi gereken bir eser." -The Economist Kendimizi, dogaustu varligin egemen oldugu yasamlardan kurtarabilecegimiz, yeni bin yilin kitabi olarak goruyorum." -Brian Eno ''...eglenceli, oldukca bilgilendirici, gorkemli yazilmis ...aldigimiz ilk dini egitimden bu yana basimiza bela olan bos inanclardan kaynaklanan bu zirvalara kapildigimiz icin zekice azarlaniyoruz'' Rod Liddle, Sunday Times ''Heyecanli ve neseli bir kitap. Dawkins, kuvvetli tezlerinin tum gucuyle kukreyerek geliyor...'' Joan Bakewell, Guardian ''Atesli, akillica, eglenceli, moral verici ve hepsinin otesinde olumcul derecede luzumlu...'' Daily Express ''Tanri Yanilgisi olaganustu ilginc bir kitap... parildayan dili ile anlatilmis bu kitap sadece okumayi bir zevk haline getirmekle kalmiyor, ayni zamanda genis bir yelpazede dusunmemiz icin beynimizi uyariyor'' Financial Times ''Dawkins, bir golge super guc tarafindan sarmalanmis, elverisli ve rahat bir ortamda bulunan bir insan dunyasina ihtiyac duymayan okuyuculara bir parca akil ve entellektuel bakis ila haz veriyor'' Herald Tribune ''Dunyayi bir kez daha yikayan, kopuklu bir bos inanc gelgitine karsi, butun kariyeri boyunca hayatin kendisinin zor ve muhtesem sebebini kanitlayan buyuk bir bilimadamindan, fevkalade savasci bir atak'' Johann Hari, Independent "Yaratiliscilar ile Tanri''ya inanlar, Dawkins''i kendilerinin bas dusmani olarak gormekte haklilar. The God Delusion''da kendinin ne muthis bir hasim oldugunu gostermektedir. Coskuyla ve heyecanla okunan bir yapit... Tam da Papa ile Islam''in birbirinden uzaklastigi bir ortama denk geldi." -The Guardian Son zamanlarda, Discover dergisi, evrimi sert ve etkili savundugu icin Richard Dawkins''i "Darwin''in Rottweiler"i olarak anmaktadir. Prospect dergisi ise onu, (umberto Eco ve Noam Chomsky ile birlikte) dunyanin ilk uc halk aydinindan biri olarak secti. Bu kez Dawkins keskin zekâsini din uzerine cevirir, d', NULL, '2016-11-13', '9789944315111.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786055794453', 'Japonya''dan Öyküler', 'Kenci Miyazava', '9786055794453', '6055794454', 'Nesin Yayinevi', 2010, NULL, 'Japonya''nin onde gelen cocuk edebiyati yazarlarindan biri olan Kenci Miyazava (1896-1933), yazarliginin, ogretmenliginin ve yerbilimciliginin yani sira toplumsal eylemlerdeki rolleriyle de tanindi.Ciftci bir ailenin cocugu olarak dogdu. Tarim ve ormancilik egitimi gordukten sonra, ayni alanda ogretmen olarak meslegini surdururken yazdigi cocuk oykuleri ve masallarla buyuk basari sagladi.Bir yandan ogretmenligi, ote yandan doga bilimleri ve siire olan yakinligi, onun gercek ile fantastik dunyanin ic ice gectigi, olaganustu pariak bir anlatim dili yakalamasini sagladi.Bu kitapta yazarin unu dunyaya yayilmis oykulerini, Japonca aslindan H. Can Erkin''in yaptigi cevirilerle okuyacaksiniz.', NULL, '2016-11-13', '9786055794453.jpg');
INSERT INTO books (slug, title, author, isbn13, isbn10, publisher, year, pages, description, status, added, cover_key) VALUES ('9786054883837', 'Aziz Nesin''in Anilari: Böyle Gelmis Böyle Gitmez', 'Aziz Nesin', '9786054883837', '6054883836', 'Nesin Yayinevi', 2015, 840, 'Aziz Nesin deyince akla hemen gulmece gelir... bir de aptallik yuzdesi uzerine unlu cumlesi. Oysa Aziz Nesin''i hakkinda kiyametler koparilan bir cumlenin cok otesinde doruga tirmandigi gulmece edebiyatinin sinirlari icerisinde degerlendirmek bile yetersiz kalir. romanlari, oykuleri, oyunlari, ani ve gunceleri, siirleri, denemeleri, mektuplari, gazete yazilariyla genis yaraticilik yelpazesini gozler onune seren Aziz Nesin, baslattigi veya parcasi oldugu pek cok toplumsal etkinlikle seckin bir aydin kisilik olarak da one cikmistir. Kurdugu Nesin Vakfi benzersiz ozelliklerinin bir simgesi olarak varligini surdurmektedir. Aziz Nesin''in ani ve gunceleri, baska hic bir eser vermeseydi onu dunya capinda bir yazar olarak selamlamamiza yetecek duzeydedir. Okuyun, goreceksiniz. (Tanitim Bulteninden)', 'In progress', '2016-11-13', '9786054883837.jpg');
